(192, 'SimplePluginLogger_plugin_info_before_update', '{\n    \"admin-menu-editor\\/menu-editor.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"Admin Menu Editor\",\n        \"PluginURI\": \"http:\\/\\/w-shadow.com\\/blog\\/2008\\/12\\/20\\/admin-menu-editor-for-wordpress\\/\",\n        \"Version\": \"1.15\",\n        \"Description\": \"Lets you directly edit the WordPress admin menu. You can re-order, hide or rename existing menus, add custom menus and more.\",\n        \"Author\": \"Janis Elsts\",\n        \"AuthorURI\": \"http:\\/\\/w-shadow.com\\/blog\\/\",\n        \"TextDomain\": \"admin-menu-editor\",\n        \"DomainPath\": \"\",\n        \"Network\": false,\n        \"RequiresWP\": \"\",\n        \"RequiresPHP\": \"7.4\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"Admin Menu Editor\",\n        \"AuthorName\": \"Janis Elsts\"\n    },\n    \"advanced-custom-fields\\/acf.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"Advanced Custom Fields\",\n        \"PluginURI\": \"https:\\/\\/www.advancedcustomfields.com\",\n        \"Version\": \"6.6.2\",\n        \"Description\": \"Customize WordPress with powerful, professional and intuitive fields.\",\n        \"Author\": \"WP Engine\",\n        \"AuthorURI\": \"https:\\/\\/wpengine.com\\/?utm_source=wordpress.org&utm_medium=referral&utm_campaign=plugin_directory&utm_content=advanced_custom_fields\",\n        \"TextDomain\": \"acf\",\n        \"DomainPath\": \"\\/lang\",\n        \"Network\": false,\n        \"RequiresWP\": \"6.2\",\n        \"RequiresPHP\": \"7.4\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"Advanced Custom Fields\",\n        \"AuthorName\": \"WP Engine\"\n    },\n    \"caters\\/index.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"CATERS BLOCKS\",\n        \"PluginURI\": \"\",\n        \"Version\": \"1.0\",\n        \"Description\": \"\\u30ab\\u30c6\\u30eb\\u682a\\u5f0f\\u4f1a\\u793e\",\n        \"Author\": \"Nguy\\u1ec5n Thanh Huy\",\n        \"AuthorURI\": \"huy.nguyenthanh@caters.co.jp\",\n        \"TextDomain\": \"caters\",\n        \"DomainPath\": \"\",\n        \"Network\": false,\n        \"RequiresWP\": \"\",\n        \"RequiresPHP\": \"\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"CATERS BLOCKS\",\n        \"AuthorName\": \"Nguy\\u1ec5n Thanh Huy\"\n    },\n    \"flexible-table-block\\/flexible-table-block.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"Flexible Table Block\",\n        \"PluginURI\": \"\",\n        \"Version\": \"3.6.0\",\n        \"Description\": \"Easily create flexible configuration tables.\",\n        \"Author\": \"Aki Hamano\",\n        \"AuthorURI\": \"https:\\/\\/github.com\\/t-hamano\",\n        \"TextDomain\": \"flexible-table-block\",\n        \"DomainPath\": \"\",\n        \"Network\": false,\n        \"RequiresWP\": \"6.8\",\n        \"RequiresPHP\": \"8.0\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"Flexible Table Block\",\n        \"AuthorName\": \"Aki Hamano\"\n    },\n    \"lazy-blocks-pro\\/lazy-blocks-pro.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"Lazy Blocks Pro\",\n        \"PluginURI\": \"\",\n        \"Version\": \"4.1.0\",\n        \"Description\": \"Easily create custom blocks and custom meta fields for Gutenberg without hard coding.\",\n        \"Author\": \"Lazy Blocks Team\",\n        \"AuthorURI\": \"https:\\/\\/lazyblocks.com\\/?utm_source=plugin_pro&utm_medium=readme&utm_campaign=byline\",\n        \"TextDomain\": \"lazy-blocks\",\n        \"DomainPath\": \"\",\n        \"Network\": false,\n        \"RequiresWP\": \"6.2\",\n        \"RequiresPHP\": \"8.0\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"Lazy Blocks Pro\",\n        \"AuthorName\": \"Lazy Blocks Team\"\n    },\n    \"radio-buttons-for-taxonomies\\/radio-buttons-for-taxonomies.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"Radio Buttons for Taxonomies\",\n        \"PluginURI\": \"http:\\/\\/www.kathyisawesome.com\\/441\\/radio-buttons-for-taxonomies\",\n        \"Version\": \"2.4.7\",\n        \"Description\": \"Use radio buttons for any taxonomy so users can only select 1 term at a time\",\n        \"Author\": \"helgatheviking\",\n        \"AuthorURI\": \"https:\\/\\/www.kathyisawesome.com\",\n        \"TextDomain\": \"radio-buttons-for-taxonomies\",\n        \"DomainPath\": \"\\/languages\\/\",\n        \"Network\": false,\n        \"RequiresWP\": \"4.5.0\",\n        \"RequiresPHP\": \"\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"Radio Buttons for Taxonomies\",\n        \"AuthorName\": \"helgatheviking\"\n    },\n    \"simple-history\\/index.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"Simple History\",\n        \"PluginURI\": \"https:\\/\\/simple-history.com\",\n        \"Version\": \"5.24.0\",\n        \"Description\": \"Plugin that logs various things that occur in WordPress and then presents those events in a very nice GUI.\",\n        \"Author\": \"P\\u00e4r Thernstr\\u00f6m\",\n        \"AuthorURI\": \"https:\\/\\/simple-history.com\\/\",\n        \"TextDomain\": \"simple-history\",\n        \"DomainPath\": \"\",\n        \"Network\": false,\n        \"RequiresWP\": \"6.3\",\n        \"RequiresPHP\": \"7.4\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"Simple History\",\n        \"AuthorName\": \"P\\u00e4r Thernstr\\u00f6m\"\n    },\n    \"wp-downgrade\\/wp-downgrade.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"WP Downgrade | Specific Core Version\",\n        \"PluginURI\": \"https:\\/\\/www.reisetiger.net\",\n        \"Version\": \"1.2.6\",\n        \"Description\": \"WP Downgrade allows you to either downgrade or update WordPress Core to an arbitrary version of your choice. The version you choose is downloaded directly from wordpress.org and installed just like any regular release update. The target version WordPress allows you to update to remains constant until you enter a different one or deactivate the plugin either completely or by leaving the target version field empty.\",\n        \"Author\": \"Reisetiger\",\n        \"AuthorURI\": \"https:\\/\\/www.reisetiger.net\",\n        \"TextDomain\": \"wp-downgrade\",\n        \"DomainPath\": \"\\/languages\",\n        \"Network\": false,\n        \"RequiresWP\": \"\",\n        \"RequiresPHP\": \"\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"WP Downgrade | Specific Core Version\",\n        \"AuthorName\": \"Reisetiger\"\n    },\n    \"duplicate-post\\/duplicate-post.php\": {\n        \"GitHub Plugin URI\": \"\",\n        \"Name\": \"Yoast Duplicate Post\",\n        \"PluginURI\": \"https:\\/\\/yoast.com\\/wordpress\\/plugins\\/duplicate-post\\/\",\n        \"Version\": \"4.5\",\n        \"Description\": \"The go-to tool for cloning posts and pages, including the powerful Rewrite & Republish feature.\",\n        \"Author\": \"Enrico Battocchi & Team Yoast\",\n        \"AuthorURI\": \"https:\\/\\/yoast.com\",\n        \"TextDomain\": \"duplicate-post\",\n        \"DomainPath\": \"\",\n        \"Network\": false,\n        \"RequiresWP\": \"\",\n        \"RequiresPHP\": \"\",\n        \"UpdateURI\": \"\",\n        \"RequiresPlugins\": \"\",\n        \"Title\": \"Yoast Duplicate Post\",\n        \"AuthorName\": \"Enrico Battocchi & Team Yoast\"\n    }\n}', 'off'),
