\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7960\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:230:\"以下は WordPress.org 公式ブログの記事「WordPress 6.9.4 Release」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 WordPress 6.9.4を利用できま [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Akira Tachibana\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3553:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://wordpress.org/news/2026/03/wordpress-6-9-4-release/\">WordPress 6.9.4 Release</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 6.9.4を利用できます !</h2>\n\n\n\n<p class=\"wp-block-paragraph\">昨日、<a href=\"https://ja.wordpress.org/2026/03/11/wordpress-6-9-2-release/\">WordPress 6.9.2</a>と<a href=\"https://ja.wordpress.org/2026/03/11/wordpress-6-9-3-and-7-0-beta-4/\">WordPress 6.9.3</a>がリリースされ、10件のセキュリティ問題と、限られたサイトでのテンプレートファイルの読み込みに影響するバグが修正されました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">しかし、WordPress セキュリティチームは、すべてのセキュリティ修正が完全に適用されていないことを発見したため、必要な追加修正を含む WordPress 6.9.4をリリースしました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">これはセキュリティリリースであるため、<strong>サイトを直ちにアップデートすることをお勧めします</strong>。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/wordpress-6.9.4.zip\">WordPress 6.9.4は WordPress.org からダウンロード</a>するか、WordPress ダッシュボードにアクセスし、「更新」をクリックし、「今すぐ更新」をクリックして適用してください。自動バックグラウンド更新に対応しているサイトの場合は、更新プロセスが自動的に始まります。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9.4の詳細については、<a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-4/\">HelpHub サイトのバージョンページ</a>をご覧ください。</p>\n\n\n\n<h2 class=\"wp-block-heading\">このリリースに含まれるセキュリティアップデート</h2>\n\n\n\n<p class=\"wp-block-paragraph\">セキュリティチームは、この問題を報告および調査した貢献者の皆様、特に責任ある情報開示をした <a href=\"https://profiles.wordpress.org/kraftner\">Thomas Kräftner</a> 氏に感謝いたします。6.9.4で解決されたセキュリティ問題は以下です。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>PclZip におけるパストラバーサルの問題:&nbsp;<a href=\"https://profiles.wordpress.org/francescocarlucci/\">Francesco Carlucci</a>&nbsp;および&nbsp;<a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a>&nbsp;による個別の報告</li>\n\n\n\n<li>ノート (Notes) 機能における権限昇格 (バイパス):&nbsp;<a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a>&nbsp;による報告</li>\n\n\n\n<li>外部 getID3 ライブラリにおける XXE:&nbsp;<a href=\"https://profiles.wordpress.org/regex33/\">Youssef Achtatal</a>&nbsp;による報告<a href=\"https://profiles.wordpress.org/kaminuma/\"></a></li>\n</ul>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">協力者:&nbsp;<a href=\"https://profiles.wordpress.org/torikumo/\">@torikumo</a>, <a href=\'https://profiles.wordpress.org/nukaga/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>nukaga</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7960\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:69:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"WordPress 6.9.3と7.0ベータ4\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"https://ja.wordpress.org/2026/03/11/wordpress-6-9-3-and-7-0-beta-4/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 11 Mar 2026 14:32:23 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:12:\"Announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"Security\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:3:\"6-9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:3:\"7-0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7948\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:240:\"以下は WordPress.org 公式ブログの記事「WordPress 6.9.3 and 7.0 beta 4」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 本日先にリリースされた Wo [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Junko Nukaga\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7758:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://wordpress.org/news/2026/03/wordpress-6-9-3-and-7-0-beta-4/\">WordPress 6.9.3 and 7.0 beta 4</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://ja.wordpress.org/2026/03/11/wordpress-6-9-2-release/\" data-type=\"link\" data-id=\"https://ja.wordpress.org/?p=7944\">本日先にリリースされた WordPress 6.9.2</a>では、10件のセキュリティ問題が解決されました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">その後、一部のユーザーから、6.9.2 への更新後にサイトのフロントエンドが空白で表示される問題が報告されました。調査の結果、原因は一部のテーマが採用している、ファイルパスに通常の文字列ではなく「Stringable オブジェクト (文字列として扱えるオブジェクト) 」を介してテンプレートファイルを読み込むという、特殊な手法に起因することが判明しました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">これは WordPress におけるテンプレートファイル読み込みの公式サポート対象手法ではありませんが (<code>template_include</code> フィルタは文字列のみを受け付ける仕様です) 、この手法が原因で一部のサイトが動作しなくなる事態が引き起こされました。そのためセキュリティチームは緊急フォローアップとして6.9.3をリリースすることを決定しました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">これまでと同様に、<strong>直ちに最新バージョンの WordPress へアップデートすることをお勧めします。</strong> これにより、6.9.2で修正されたすべてのセキュリティ対策を適用しつつ、6.9.3で修正された不具合の影響も回避できます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">問題の報告、原因の特定、および修正に協力してくださった皆さまに深く感謝いたします。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/wordpress-6.9.3.zip\">WordPress 6.9.3は WordPress.org からダウンロードする</a>か、ダッシュボードの「更新」画面で「今すぐ更新」をクリックしてください。自動バックグラウンド更新を有効にしている場合は、間もなく自動的に更新が始まりますので、操作は不要です。 詳細については、HelpHub の<a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-3/\" target=\"_blank\" rel=\"noreferrer noopener\">バージョンページ</a>をご確認ください。</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 7.0ベータ4</h2>\n\n\n\n<p class=\"wp-block-paragraph\">次回のメジャーリリースである <a href=\"https://make.wordpress.org/core/7-0/\">WordPress 7.0</a>は、2026年4月9日の公開を予定しています。セキュリティチームは、次期リリースのテストに尽力しているコミュニティメンバーを含むすべてのユーザーを脆弱性から保護するため、新しいベータ版 (7.0 Beta 4) を公開することを決定しました。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>これは7.0リリースサイクルにおける追加のベータリリースとなります。</strong>今後のスケジュールに変更はなく、当初予定されていた全4回のベータリリースの代わりに、合計5回のベータ版が公開されます。次回の7.0ベータ版リリースは依然として3月12日 (木) を予定しています。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>この WordPress ソフトウェアのベータ版は開発中です。</strong>このバージョンの WordPress を本番環境やミッションクリティカルなウェブサイトでインストール、実行、テストしないでください。新機能を試すには、代わりにテスト環境やローカルサイトをセットアップしてください。</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong><strong>WordPress Beta Tester プラグイン</strong></strong></td><td><a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a>&nbsp;プラグインをインストールして有効化する。設定では「最前線」チャンネルと「ベータ / RC のみ」ストリームを選択します。</td></tr><tr><td><strong><strong>直接ダウンロード</strong></strong></td><td><a href=\"https://wordpress.org/wordpress-7.0-beta4.zip\">Beta 4 version (zip)</a>&nbsp;をダウンロードして、WordPress ウェブサイトにインストールする。</td></tr><tr><td><strong><strong>コマンドライン (WP-CLI)</strong></strong></td><td><a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>&nbsp;コマンドを実行する。<br><code>wp core update --version=7.0-beta</code>4</td></tr><tr><td><strong><strong>WordPress Playground</strong></strong></td><td><a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">WordPress Playground instance</a>&nbsp;を使用する。ブラウザで直接ソフトウェアをテストできます。個別のサイトやセットアップは必要ありません。</td></tr></tbody></table></figure>\n\n\n\n<h2 class=\"wp-block-heading\">ベータ4の更新内容と主な変更点</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 ベータ4には、WordPress 6.9.2で提供された10件のセキュリティパッチに加え、ベータ3リリース以降に実施された49件以上の更新と修正が含まれています。内訳はエディター関連が14件、コア関連が35件です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">各ベータサイクルはバグ修正に重点を置いています。皆様のテスト協力により、さらなる修正が進行中です。ベータ3以降の全修正内容の技術的詳細は以下のリンクで確認できます。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>2026年3月5日以降の<a href=\"https://github.com/WordPress/gutenberg/compare/f4d8a5803aa2fbe26e7d9af4d17e80a622b7bab8...9b8144036fa5faf75de43d4502ff9809fcf689ad\">7.0 対象の GitHub コミット一覧</a></li>\n\n\n\n<li>2026年3月5日以降に<a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F05%2F2026..03%2F10%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">クローズされた Trac チケット一覧</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">リリース成功の鍵は、テスト段階での皆さまの確認作業にあります。ぜひダウンロードしてテストをお願いします！</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em><a href=\"https://profiles.wordpress.org/peterwilson/\">@peterwilson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj/\">@desrosj</a>,&nbsp;<a href=\"https://profiles.wordpress.org/marybaum/\">@marybaum</a>,&nbsp;<a href=\"https://profiles.wordpress.org/amykamala/\">@amykamala</a>&nbsp;</em>のレビューに感謝します。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">協力者:&nbsp;<a href=\"https://profiles.wordpress.org/atachibana/\">@atachibana</a>,&nbsp;<a href=\"https://profiles.wordpress.org/torikumo/\">@torikumo</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7948\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"WordPress 6.9.2 リリース\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://ja.wordpress.org/2026/03/11/wordpress-6-9-2-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 11 Mar 2026 14:31:33 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:12:\"Announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"Security\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7944\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:228:\"以下は WordPress.org 公式ブログの記事「WordPress 6.9.2 Release」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 WordPress 6.9.2 が利用可能 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Junko Nukaga\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6190:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://wordpress.org/news/2026/03/wordpress-6-9-2-release/\">WordPress 6.9.2 Release</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 6.9.2 が利用可能です !</h2>\n\n\n\n<p class=\"wp-block-paragraph\">今回のリリースは、複数の修正を含む<strong>セキュリティリリース</strong>です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">セキュリティ保護のため、サイトを<strong>直ちにアップデートすることをお勧めします。</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9.2 は、<a href=\"https://wordpress.org/wordpress-6.9.2.zip\">WordPress.org からダウンロードする</a>か、ダッシュボードの「更新」画面で「今すぐ更新」をクリックして適用してください。自動バックグラウンド更新を有効にしている場合は、自動的に更新プロセスが開始されます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">次回のメジャーリリースは<a href=\"https://make.wordpress.org/core/7-0/\">バージョン 7.0</a>を予定しており、2026年4月9日に公開される予定です。 </p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9.2の詳細については、<a href=\"https://wordpress.org/documentation/wordpress-version/version-6-9-2/\">HelpHub サイトのバージョンページ</a>をご覧ください。</p>\n\n\n\n<h2 class=\"wp-block-heading\">このリリースに含まれるセキュリティ修正</h2>\n\n\n\n<p class=\"wp-block-paragraph\">セキュリティチームは、以下の<a href=\"https://hackerone.com/wordpress?type=team\">脆弱性を責任を持って報告し</a>、修正に協力してくれた方々に感謝いたします。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>ブラインド SSRF の問題: <a href=\"https://hackerone.com/sibwtf\">sibwtf</a>、および修正作業中に報告を寄せた複数の研究者による報告</li>\n\n\n\n<li>HTML API およびブロックレジストリにおける PoP チェーンの弱点: <a href=\"https://github.com/hackerlo2003\">Phat RiO</a> による報告</li>\n\n\n\n<li>数値文字参照における正規表現 DoS (ReDoS) の弱点: WordPress セキュリティチームの Dennis Snell による報告</li>\n\n\n\n<li>ナビゲーションメニューにおける蓄積型 XSS: <a href=\"https://x.com/Savphill\">Phill Savage</a> による報告</li>\n\n\n\n<li>AJAX <code>query-attachments</code> における認証回避の脆弱性: <a href=\"https://www.vitalysim.com/\">Vitaly Simonovich</a> による報告</li>\n\n\n\n<li><code>data-wp-bind</code> ディレクティブを介した蓄積型 XSS: <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a> による報告</li>\n\n\n\n<li>管理画面でのクライアントサイドテンプレートのオーバーライドを許す XSS: <a href=\"https://hackerone.com/amosec\">Asaf Mozes</a> による報告</li>\n\n\n\n<li>PclZip におけるパストラバーサルの問題: <a href=\"https://profiles.wordpress.org/francescocarlucci/\">Francesco Carlucci</a> および <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a> による個別の報告。</li>\n\n\n\n<li>ノート (Notes) 機能における権限昇格 (バイパス): <a href=\"https://profiles.wordpress.org/kaminuma/\">kaminuma</a> による報告</li>\n\n\n\n<li>外部 getID3 ライブラリにおける XXE: <a href=\"https://profiles.wordpress.org/regex33/\">Youssef Achtatal</a> による報告</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress セキュリティチームは、getID3 のメンテナである James Heinrich と協力し、getID3 の修正を調整しました。新しいバージョンの getID3 は<a href=\"https://github.com/JamesHeinrich/getID3\" target=\"_blank\" rel=\"noreferrer noopener\">こちら</a>から入手可能です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">これらの修正は、セキュリティ修正の対象となるすべてのブランチ (現在は4.7以降) に必要に応じてバックポートされます。なお、<strong>現在アクティブにサポートされているのは最新バージョンのみです</strong>。バックポートは現在進行中であり、準備が整い次第配信されます。</p>\n\n\n\n<h2 class=\"wp-block-heading\">貢献者の皆さまへの感謝</h2>\n\n\n\n<p class=\"wp-block-paragraph\">今回のリリースは <a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a> がリードしました。前述のセキュリティ研究者に加え、以下の皆さまの協力がなければ WordPress 6.9.2 のリリースは実現しませんでした。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/dmsnell/\">Dennis Snell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jonsurrell/\">Jon Surrell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/isabel_brison/\">Isabel Brison</a>,&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/luisherranz/\">Luis Herranz</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>,&nbsp;<a href=\"https://profiles.wordpress.org/westonruter/\">Weston Ruter</a>, and&nbsp;<a href=\"https://profiles.wordpress.org/ocean90/\">Dominik Schilling</a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">協力者:&nbsp;<a href=\'https://profiles.wordpress.org/atachibana/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>atachibana</a>,&nbsp;<a href=\'https://profiles.wordpress.org/torikumo/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>torikumo</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7944\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"WordPress 7.0 ベータ3\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://ja.wordpress.org/2026/03/06/wordpress-7-0-beta-3/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 06 Mar 2026 13:14:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7930\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:238:\"以下は WordPress.org 公式ブログの記事「WordPress 7.0 Beta 3」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 WordPress 7.0ベータ3がリリースされ [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Itsuko Miyake\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8443:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-beta-3/\">WordPress 7.0 Beta 3</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ3がリリースされました。ダウンロードして、テストをお願いします。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>この WordPress ソフトウェアのベータ版は開発中です。</strong>このバージョンの WordPress を本番環境やミッションクリティカルなウェブサイトでインストール、実行、テストしないでください。新機能を試すには、代わりにテスト環境やローカルサイトをセットアップしてください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ3は以下のどの方法でもテストできます。</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>WordPress Beta Tester プラグイン</strong></td><td><a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a>&nbsp;プラグインをインストールして有効化する。設定では「最前線」チャンネルと「ベータ / RC のみ」ストリームを選択します。</td></tr><tr><td><strong>直接ダウンロード</strong></td><td><a href=\"https://wordpress.org/wordpress-7.0-beta2.zip\"></a><a href=\"https://wordpress.org/wordpress-7.0-beta3.zip\">Beta 3 version (zip)</a>&nbsp;をダウンロードして、WordPress ウェブサイトにインストールする。</td></tr><tr><td><strong>コマンドライン (WP-CLI)</strong></td><td><a href=\"https://make.wordpress.org/cli/\"></a><a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>&nbsp;コマンドを実行する。<code>wp core update --version=7.0-beta3</code></td></tr><tr><td><strong>WordPress Playground</strong></td><td><a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language&amp;multisite=no&amp;random=y4q1rn88xn\">7.0 Beta 3 WordPress Playground instance</a>&nbsp;を使用する。ブラウザで直接ソフトウェアをテストできます。個別のサイトやセットアップは必要ありません。</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0の最終リリース予定日は<strong>2026年4月9日</strong>です。完全な<a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">リリーススケジュールはこちらで確認できます</a>。ベータ版および RC 版のテストへのご協力が、このリリースを可能な限り安定かつ強力なものにするために不可欠です。今後数週間の&nbsp;<a href=\"https://make.wordpress.org/core/\">Make WordPress Core ブログ</a>の<a href=\"https://make.wordpress.org/core/tag/7-0/\">7.0関連記事</a>をチェックして、追加の詳細情報を確認してください。テストを通じて貢献するみなさんに感謝します !</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress 7.0の新機能をキャッチアップ:</strong>&nbsp;<a href=\"https://ja.wordpress.org/2026/02/28/wordpress-7-0-beta-2/\">7.0の詳細とハイライトについてはベータ2の告知を参照してください。</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 7.0ベータ3をテストする方法</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0のリリースが最高の形で実現するためには、現段階のベータバージョンのテストに協力いただくことが極めて重要です。アップグレードのプロセスをテストいただくことも、また新しく追加された機能を試していただくことも、どちらも等しく重要です。WordPress 7.0の機能テストの手順については、<a href=\"https://ja.wordpress.org/2026/02/27/help-test-wordpress-7-0/\">こちらのガイド</a>を参照してください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">問題に遭遇したら、まずサポートフォーラムの<a href=\"https://wordpress.org/support/forum/alphabeta/\">アルファ・ベータエリア</a>に報告をしてください。再現可能なバグ報告の作成に慣れている方は&nbsp;<a href=\"https://core.trac.wordpress.org/newticket\">WordPress Trac</a>&nbsp;への報告をお願いします。<a href=\"https://core.trac.wordpress.org/tickets/major\">既知のバグ</a>の一覧も Trac で閲覧可能です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">リリースのテスト全般について知りたければ、<a href=\"https://make.wordpress.org/test/\">Make Core におけるテスト関連タスク</a>をフォローし、<a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>&nbsp;の&nbsp;<a href=\"https://wordpress.slack.com/messages/core-test/\">#core-test チャンネル</a>に参加してください。</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 7.0ベータ3のアップデートとハイライト</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ3には、ベータ2のリリース以来、エディター70件、コア78件を含む148件以上の更新と修正が含まれています。</p>\n\n\n\n<p class=\"wp-block-paragraph\">各ベータのサイクルはバグ修正に焦点を当てており、テストを通じた皆さんの支援によりさらに多くの修正が進められています。以下のリンクから、ベータ2以降に対応したすべての問題の技術的な詳細を閲覧することができます。</p>\n\n\n\n<ul id=\"block-20be1c21-55ba-49f7-83f9-e394a77ed3f9\" class=\"wp-block-list\">\n<li>2026年2月20日以降の<a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-02-20&amp;until=2026-02-26\">7.0 対象の GitHub コミット一覧</a></li>\n\n\n\n<li>2026年2月20日以降に<a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=02%2F20%2F2026..02%2F26%2F2026&amp;milestone=7.0&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">クローズされた Trac&nbsp;</a><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F05%2F2025..03%2F10%2F2025&amp;milestone=6.8&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">チケット</a><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=10%2F02%2F2024..10%2F07%2F2024&amp;milestone=6.7&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">一覧</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">ベータ3では、AI の機能をさらに簡単に活用できるようになりました。WP AI Client Connectors 画面では、3つのデフォルトプロバイダーに加えて、WP AI Client レジストリからプロバイダーを動的に登録できるようになりました。これにより、AI 連携においてより高い柔軟性とコントロールが可能になります。</p>\n\n\n\n<h3 class=\"wp-block-heading\">ベータ3の俳句</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Through sun set and rise,<br>Beta 3 takes off and flies.<br>Seven soon arrives.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">昼と夜重ね<br>飛び立つベータ3<br>7.0まもなく</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Props to&nbsp;<a href=\"https://profiles.wordpress.org/annezazu/\">@annezazu</a></em>,&nbsp;<em><a href=\"https://profiles.wordpress.org/jeffpaul/\">@jeffpaul</a></em>,&nbsp;<em><a href=\"https://profiles.wordpress.org/chaion07/\">@chaion07</a></em>,<em>&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a>&nbsp;and&nbsp;<a href=\"https://profiles.wordpress.org/valentingrenier/\">@valentingrenier</a>&nbsp;</em> <em>コラボレーション、校正、レビューに対して。</em></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">協力者: <a href=\'https://profiles.wordpress.org/nukaga/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>nukaga</a>, <a href=\'https://profiles.wordpress.org/atachibana/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>atachibana</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7930\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"WordPress 7.0 ベータ2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://ja.wordpress.org/2026/02/28/wordpress-7-0-beta-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 28 Feb 2026 07:35:01 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7918\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:238:\"以下は WordPress.org 公式ブログの記事「WordPress 7.0 Beta 2」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 WordPress 7.0ベータ2がリリースされ [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Itsuko Miyake\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9072:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://wordpress.org/news/2026/02/wordpress-7-0-beta-2/\">WordPress 7.0 Beta 2</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ2がリリースされました。ダウンロードして、テストをお願いします。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>この WordPress ソフトウェアのベータ版は開発中です。</strong>このバージョンの WordPress を本番環境やミッションクリティカルなウェブサイトでインストール、実行、テストしないでください。新機能を試すには、代わりにテスト環境やローカルサイトをセットアップしてください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ2は以下のどの方法でもテストできます。</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>WordPress Beta Tester プラグイン</strong></td><td><a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a>&nbsp;プラグインをインストールして有効化する。設定では「最前線」チャンネルと「ベータ / RC のみ」ストリームを選択します。</td></tr><tr><td><strong>直接ダウンロード</strong></td><td><a href=\"https://wordpress.org/wordpress-7.0-beta2.zip\">Beta 2 version (zip)</a>&nbsp;をダウンロードして、WordPress ウェブサイトにインストールする。</td></tr><tr><td><strong>コマンドライン (WP-CLI)</strong></td><td><a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>&nbsp;コマンドを実行する。<code>wp core update --version=7.0-beta2</code></td></tr><tr><td><strong>WordPress Playground</strong></td><td><a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">7.0 Beta 2 WordPress Playground instance</a>&nbsp;を使用する。ブラウザで直接ソフトウェアをテストできます。個別のサイトやセットアップは必要ありません。</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0の最終リリース予定日は<strong>2026年4月9日</strong>です。完全な<a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">リリーススケジュールはこちらで確認できます</a>。ベータ版および RC 版のテストへのご協力が、このリリースを可能な限り安定かつ強力なものにするために不可欠です。今後数週間の <a href=\"https://make.wordpress.org/core/\">Make WordPress Core ブログ</a>の<a href=\"https://make.wordpress.org/core/tag/7-0/\">7.0関連記事</a>をチェックして、追加の詳細情報を確認してください。テストを通じて貢献するみなさんに感謝します !</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress 7.0の新機能をキャッチアップ:</strong>&nbsp;<a href=\"https://ja.wordpress.org/2026/02/23/wordpress-7-0-beta-1/\">7.0の詳細とハイライトについてはベータ1の告知を参照してください。</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 7.0ベータ2をテストする方法</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0のリリースが最高の形で実現するためには、現段階のベータバージョンのテストに協力いただくことが極めて重要です。アップグレードのプロセスをテストいただくことも、また新しく追加された機能を試していただくことも、どちらも等しく重要です。WordPress 7.0の機能テストの手順については、<a href=\"https://ja.wordpress.org/2026/02/27/help-test-wordpress-7-0/\">こちらのガイド</a>を参照してください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">問題に遭遇したら、まずサポートフォーラムの<a href=\"https://wordpress.org/support/forum/alphabeta/\">アルファ・ベータエリア</a>に報告をしてください。再現可能なバグ報告の作成に慣れている方は&nbsp;<a href=\"https://core.trac.wordpress.org/newticket\">WordPress Trac</a>&nbsp;への報告をお願いします。<a href=\"https://core.trac.wordpress.org/tickets/major\">既知のバグ</a>の一覧も Trac で閲覧可能です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">リリースのテスト全般について知りたければ、<a href=\"https://make.wordpress.org/test/\">Make Core におけるテスト関連タスク</a>をフォローし、<a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>&nbsp;の&nbsp;<a href=\"https://wordpress.slack.com/messages/core-test/\">#core-test チャンネル</a>に参加してください。</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 7.0ベータ2のアップデートとハイライト</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ2にはベータ1のリリース以来、70件以上のエディターとコアに関する更新と修正が含まれています。</p>\n\n\n\n<p class=\"wp-block-paragraph\">各ベータのサイクルはバグ修正に焦点を当てており、テストを通じた皆さんの支援によりさらに多くの修正が進められています。以下のリンクから、ベータ1以降に対応したすべての問題の技術的な詳細を閲覧することができます。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>2026年2月20日以降の<a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-02-20&amp;until=2026-02-26\">7.0 対象の GitHub コミット一覧</a></li>\n\n\n\n<li>2026年2月20日以降に<a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=02%2F20%2F2026..02%2F26%2F2026&amp;milestone=7.0&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">クローズされた Trac&nbsp;</a><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F05%2F2025..03%2F10%2F2025&amp;milestone=6.8&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">チケット</a><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=10%2F02%2F2024..10%2F07%2F2024&amp;milestone=6.7&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">一覧</a></li>\n</ul>\n\n\n\n<h4 class=\"wp-block-heading\">ベータ2に新しい機能が含まれています !</h4>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ2では、新しいコネクター UI ダッシュボードページにより、AI プロバイダーの管理がさらに直感的になりました。WordPress ユーザーは、wp-admin の「設定」-&gt; 「コネクター」下にある一元的な場所で、外部 AI との接続を管理できます。新しい UI では、外部接続の追加、削除、更新が可能です。この UI は拡張可能なルートベースのアーキテクチャを採用しており、プラグインやテーマがページにフックして機能を拡張できます。「コネクター」ページは PHP ベースのスクリプトとメニュー基盤の上に構築され、<code>@wordpress/components</code> と <code>@wordpress/admin-ui</code> によるルートコンポーネントを追加します。新しい <code>connections-wp-admin-init</code> フックと登録 API により、プラグインはクリーンに統合できます。これにより、外部接続の管理が容易になると同時に、開発者にはエクスペリエンスを拡張するための明確な道筋が提供されます。</p>\n\n\n\n<h3 class=\"wp-block-heading\">ベータ2の俳句</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>New, and fresh as dew<br>Crafted and refined for you:<br>Beta 2 breaks through.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">露新た<br>磨き重ねて<br>ベータ2殻破る</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Props to&nbsp;<a href=\"https://profiles.wordpress.org/4thhubbard/\">@4thhubbard</a>,&nbsp;<a href=\"https://profiles.wordpress.org/annezazu/\">@annezazu</a></em>,&nbsp;<em><a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mukesh27/\">@mukesh27</a>, and&nbsp;<a href=\"https://profiles.wordpress.org/chaion07/\">@chaion07</a></em>&nbsp;<em>コラボレーション、校正、レビューに対して。</em></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">協力者: <a href=\'https://profiles.wordpress.org/nukaga/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>nukaga</a>, <a href=\'https://profiles.wordpress.org/atachibana/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>atachibana</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7918\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"PHP 7.2および7.3のサポート終了\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://ja.wordpress.org/2026/02/27/dropping-support-for-php-7-2-and-7-3/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 26 Feb 2026 16:10:10 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:12:\"Announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"Security\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7906\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:220:\"以下は WordPress.org 公式ブログの記事「Dropping support for PHP 7.2 and 7.3」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 PHP 7.2お [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Akira Tachibana\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6528:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://make.wordpress.org/core/2026/01/09/dropping-support-for-php-7-2-and-7-3/\">Dropping support for PHP 7.2 and 7.3</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">PHP 7.2および7.3のサポートは<a href=\"https://make.wordpress.org/core/7-0/\">、2026年4月にリリース予定の WordPress 7.0</a>で終了します。PHP の<em>推奨される最小バージョンは</em>8.3のままですが、<em>サポートされる最小バージョン</em>は新しく7.4.0になります。</p>\n\n\n\n<p class=\"wp-block-paragraph\">PHP の最小サポートバージョンは、2024年7月に7.2.24に引き上げられました。それ以降、PHP 7.2および7.3の使用率は、<a href=\"https://wordpress.org/about/stats/\">監視対象の WordPress のインストールレベルで4%を下回っています</a>。</p>\n\n\n\n<p class=\"wp-block-paragraph\">歴史的にプロジェクトでは PHP バージョンの廃止を検討する基準として、5% の使用率という数字を使用してきました。現在、PHP 7.2と7.3を合わせた使用率がこの基準を大きく下回っているため、サポート対象となるPHPバージョンの最小値を引き上げるプロセスを進めています。</p>\n\n\n\n<p class=\"wp-block-paragraph\">PHP の最小サポートバージョンを引き上げる目的は、WordPress の長期的なメンテナンス性の確保にあります。PHP の最小サポートバージョンを引き上げるメリットは時間とともにさまざまな領域で現れてきます。たとえばプラグインとテーマのエコシステム、AI 用のツールとライブラリ、WordPress プロジェクトの長期的な認知度、開発者との連携、そして最終的には、開発者ツールや自動テスト基盤を含む WordPress のコードベース自体など。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://core.trac.wordpress.org/ticket/62622\">この最小サポートバージョンの引き上げに関する議論は、Trac チケットを参照してください</a>。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>PHP 8以上のサポートはどうなりますか ?</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress のコアは PHP 8.0から8.3まで完全に互換性があり、PHP 8.4および8.5 と<a href=\"https://make.wordpress.org/core/2025/04/09/php-8-support-clarification/\">ベータ互換性があります。</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/handbook/references/php-compatibility-and-wordpress-versions/\">どの PHP バージョンが WordPress の各バージョンと互換性があるかについての詳細については、WordPress コアハンドブックを参照してください</a>。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>セキュリティサポートはありますか ?</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">PHP 7.2または7.3を使用しているサイトは、7.0がリリースされても WordPress 6.9ブランチのままとなります。セキュリティアップデートは公式には1つのブランチのみに作成されますが、<a href=\"https://make.wordpress.org/security/2025/06/18/security-updates-will-cease-for-wordpress-versions-4-1-through-4-6/\">修正は可能な限り WordPress 4.7までにバックポートされます</a>。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Gutenberg </strong><strong>プラグインはどうなりますか ?</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://github.com/WordPress/gutenberg/issues/74456\">Gutenberg プラグインも、サポートされる PHP の最小バージョンが7.4に引き上げられる予定です</a>。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>今後</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">サポートされる PHP の最小バージョンを、決まったスケジュールで引き上げる予定はありません。コアチームは引き続き PHP バージョンの使用状況を監視し、ホスティングチームと協力して、ユーザーとホスティング会社が可能な限り迅速に PHP のバージョンを引き上げるよう推進します。5%の使用率しきい値は、当面の間、引き続き標準として使用されます。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/about/stats/\">この記事の公開時点での PHP バージョンの使用状況は次のとおりです。</a></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>8.5: 0.23%</li>\n\n\n\n<li>8.4: 4.90%</li>\n\n\n\n<li>8.3: 16.74%</li>\n\n\n\n<li>8.2: 27.29%</li>\n\n\n\n<li>8.1: 15.39%</li>\n\n\n\n<li>8.0: 5.69%</li>\n\n\n\n<li>7.4: 22.20%</li>\n\n\n\n<li>7.3: 2.04%</li>\n\n\n\n<li>7.2: 1.81%</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>今すぐ PHP を更新しましょう</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">PHP やそのアップデート方法についてさらに詳しく知りたい場合は、 <a href=\"https://wordpress.org/support/update-php/\">こちら</a>のサポート記事を参照してください。詳細な説明、手順全体のガイド、ウェブホスティングプロバイダーへの問い合わせ手順が記載されています。</p>\n\n\n\n<p class=\"wp-block-paragraph\">この議論に参加してくれたすべての方々に感謝します。Thanks to <a href=\"https://profiles.wordpress.org/desrosj/\">@desrosj</a>, <a href=\"https://profiles.wordpress.org/westonruter/\">@westonruter</a>, <a href=\"https://profiles.wordpress.org/jorbin/\">@jorbin</a> この投稿へのフィードバックと校正に対して。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/tag/7-0/\"># 7-0</a>、<a href=\"https://make.wordpress.org/core/tag/dev-notes/\"> #開発ノート</a>、<a href=\"https://make.wordpress.org/core/tag/php/\"> # php</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">&#8212;</p>\n\n\n\n<p class=\"wp-block-paragraph\">協力者: <a href=\'https://profiles.wordpress.org/torikumo/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>torikumo</a>、 <a href=\'https://profiles.wordpress.org/nukaga/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>nukaga</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7906\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:67:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n\n\n\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"WordPress 7.0 テストガイド\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://ja.wordpress.org/2026/02/27/help-test-wordpress-7-0/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 26 Feb 2026 16:08:36 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:12:\"Announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:7:\"Testing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7902\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:248:\"以下は WordPress.org 公式ブログの記事「Help Test WordPress 7.0」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 2026年最初のメジャーリリースとなる W [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:4:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:71:\"https://make.wordpress.org/test/files/2026/02/Visual-Revisions-Demo.mp4\";s:6:\"length\";s:7:\"7654296\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:80:\"https://make.wordpress.org/test/files/2026/02/Font-Library-For-Classic-theme.mp4\";s:6:\"length\";s:7:\"1398721\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:73:\"https://make.wordpress.org/test/files/2026/02/Responsive-Editing-Mode.mp4\";s:6:\"length\";s:7:\"5288714\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:63:\"https://make.wordpress.org/test/files/2026/02/Coat-of-Paint.mp4\";s:6:\"length\";s:7:\"2462045\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Akira Tachibana\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:55132:\"\n<p class=\"wp-block-paragraph\">以下は <a href=\"https://wordpress.org/\">WordPress.org</a> 公式ブログの記事「<a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">Help Test WordPress 7.0</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">2026年最初のメジャーリリースとなる WordPress 7.0が間もなく登場します。正式リリースは2026年4月9日の予定です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">そして、WordPress 7.0のベータ1がリリースされました。すべてのテストの始まりです。テストは、新しい WordPress が世界中のユーザーにとって、安定的で信頼性が高く、使いやすいものにする最高の方法です。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>早期のテストが重要です !</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">解決する時間がまだあるうちにバグ、ユーザビリティ上の問題、互換性の問題を発見しましょう。</p>\n\n\n\n<p class=\"wp-block-paragraph\">あなたのテストが、リリース時に明確に実感できる改善につながっているかもしれません。</p>\n\n\n\n<p class=\"wp-block-paragraph\">数分しかない ? あるいは数時間 ? 少しのテストでも大きな違いが生まれます。7.0の新機能が実装されるかどうかが、あなたのテストで変わるかもしれません。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>最新情報を入手しましょう !</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0<a href=\"https://make.wordpress.org/core/7-0/\">リリーススケジュール</a>ページには、最新のプレリリースビルドとマイルストーンについて知るべきすべての情報が掲載されています。</p>\n\n\n\n<p class=\"wp-block-paragraph\">リアルタイムの更新については Making WordPress Slack 内の #core-test と #core チャンネルで議論をフォローし、コラボレーションの機会を見つけてください。両方のチャンネルに参加してください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">リリースサイクル全体とそれ以降のリリースパーティー、テストセッション、テストスクラブへの参加も歓迎します。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>ありがとうございます !</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">あなたはすでにヒーローです。知っていましたか ? あなたのどんな参加でも、たとえこの投稿を読むだけでも、WordPress 7.0がこれまでで最も強力で、洗練されたリリースになることを支援しています。</p>\n\n\n\n<p class=\"wp-block-paragraph\">さらに、WordPress 7.0に追加される新機能をテストすることで、WordPress 7.0がコミュニティ全体にとって大ヒットリリースとなることにつながります。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>テストのコツ</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress のテストに協力するために、認定ソフトウエアテスターやプロの品質保証技術者やその他の専門家である必要はありません。</p>\n\n\n\n<p class=\"wp-block-paragraph\">普段のように WordPress を使用するだけです (もちろんテスト環境で)。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress をハードに使ってください。プロジェクト、ワークフロー、実験を模したプロセスを実行してください。WordPress を壊すつもりで激しく。</p>\n\n\n\n<p class=\"wp-block-paragraph\">予期しないことが起きた ? バグに遭遇した ? 機能が期待通りに動作しない ? 是非、報告を検討してください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">期待される動作がわからない ? 心配ありません ! Making WordPress Slack の&nbsp; #core-test&nbsp; チャンネル内の会話に参加してください。コントリビューターや開発者がいつでも喜んでお手伝いします。チケットシステムに慣れている場合は、WordPress Trac でチケットを作成することもできます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">新しいテスターですか ? 世界中の WordPress コミュニティがお手伝いします。あなたを歓迎し、サポートします。</p>\n\n\n\n<p class=\"wp-block-paragraph\">繰り返しになりますが、提出されるすべてのレポート、質問、意見は大きな違いを生み、何億人ものユーザーのために WordPress の改善に役立ちます。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPressベータ版 / リリース候補版のテストに関する推奨事項:</strong></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>あなたにとって重要なコア機能をテストする</strong>: 普段のようにサイトを操作してください。例えば、ブロガー、ソーシャルプラットフォームの運営者、eコマースストアの管理者であれば、それぞれのシナリオでテストを実行してください。</li>\n\n\n\n<li><strong>ステージングサイト</strong>&nbsp; を構築してください (わからなければ、ホスティングプロバイダーに問い合わせてください)。テストのために、<strong>本番サイトを使用してベータ版のテストや更新をしないでください</strong>。問題が発生すると、ユーザーが目にする可能性があります。</li>\n\n\n\n<li>ステージング環境で WordPress を更新します。通常通りにサイトを使い続けてください。</li>\n\n\n\n<li>更新後に発生したすべての問題をメモしてください。</li>\n\n\n\n<li>以下の「一般的なチェックリスト」を使用して、すべてが期待どおりに動作することを確認してください。</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>WordPress ベータ版のテスト方法</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress ベータ版はいくつかの方法でテストできます。高速で簡単な方法もあれば、最新のバックエンド機能に対して高度なテストを実行できる方法もあります。</p>\n\n\n\n<p class=\"wp-block-paragraph\">これらどの方法でも、あなたの本番サイトは未知の問題の影響から保護されます。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>WordPress Playground</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/playground/\">Playground</a> は、テストサイトをすばやく簡単に立ち上げられます。完全な環境を構築する必要はありません。<a href=\"https://playground.wordpress.net/?mode=seamless&amp;language=ja&amp;multisite=no#%7B%22preferredVersions%22:%7B%22php%22:%228.3%22,%22wp%22:%22beta%22%7D,%22features%22:%7B%22networking%22:true%7D,%22steps%22:%5B%7B%22step%22:%22defineWpConfigConsts%22,%22consts%22:%7B%22WP_AUTO_UPDATE_CORE%22:false,%22DISABLE_WP_CRON%22:true%7D%7D,%7B%22step%22:%22login%22,%22username%22:%22admin%22,%22password%22:%22password%22%7D,%7B%22step%22:%22installPlugin%22,%22pluginData%22:%7B%22resource%22:%22wordpress.org/plugins%22,%22slug%22:%22query-monitor%22%7D,%22options%22:%7B%22activate%22:false%7D,%22progress%22:%7B%22weight%22:2%7D%7D,%7B%22step%22:%22installPlugin%22,%22pluginData%22:%7B%22resource%22:%22wordpress.org/plugins%22,%22slug%22:%22create-block-theme%22%7D,%22progress%22:%7B%22weight%22:2%7D%7D,%7B%22step%22:%22installPlugin%22,%22pluginData%22:%7B%22resource%22:%22wordpress.org/plugins%22,%22slug%22:%22debug-bar%22%7D,%22progress%22:%7B%22weight%22:2%7D%7D,%7B%22step%22:%22installPlugin%22,%22pluginData%22:%7B%22resource%22:%22wordpress.org/plugins%22,%22slug%22:%22health-check%22%7D,%22progress%22:%7B%22weight%22:2%7D%7D,%7B%22step%22:%22installPlugin%22,%22pluginData%22:%7B%22resource%22:%22wordpress.org/plugins%22,%22slug%22:%22test-reports%22%7D,%22progress%22:%7B%22weight%22:2%7D%7D,%7B%22step%22:%22installPlugin%22,%22pluginData%22:%7B%22resource%22:%22wordpress.org/plugins%22,%22slug%22:%22user-switching%22%7D,%22progress%22:%7B%22weight%22:2%7D%7D,%7B%22step%22:%22importWxr%22,%22file%22:%7B%22resource%22:%22url%22,%22url%22:%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%7D%7D,%7B%22step%22:%22importWxr%22,%22file%22:%7B%22resource%22:%22url%22,%22url%22:%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%7D%7D%5D%7D\">WordPress Playground で始める</a>。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>コンピュータ上のローカルサイト</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://localwp.com/\">Local</a>&nbsp; や&nbsp; <a href=\"https://developer.wordpress.org/block-editor/getting-started/devenv/get-started-with-wp-env/\">wp-env</a>&nbsp; などのソフトウェアを使えば、コンピュータ上に完全な WordPress サイトを構築できます。インターネット接続は必要ありません。</p>\n\n\n\n<p class=\"wp-block-paragraph\">サイトのセットアップ方法は以下の通りです。</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li><a href=\"https://localwp.com/\">Local</a> をダウンロードしてインストールします。</li>\n\n\n\n<li>新しい WordPress サイトを作成します。</li>\n\n\n\n<li>サイトが稼働したら、WordPress Beta Tester プラグインをインストールして有効化します。このプラグインを使用すると、WordPress のプレリリースバージョンをインストールできます。</li>\n\n\n\n<li>WordPress の開発版またはベータ版に切り替えます。</li>\n\n\n\n<li>「ツール」 -&gt; 「ベータテスト」に移動します。</li>\n\n\n\n<li>テストする内容に応じて、Bleeding Edge または Point Release Nightlies を選択します。</li>\n\n\n\n<li>「変更を保存」をクリックし、</li>\n\n\n\n<li>WordPress のバージョンを更新します。</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">詳細な手順については、<a href=\"https://make.wordpress.org/core/handbook/testing/beta-testing/\">こちらのガイド</a>をご覧ください。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>WP-CLI 経由</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">コマンドラインに慣れていますか ?&nbsp; <a href=\"https://developer.wordpress.org/cli/commands/core/update/\">WP-CLI</a>&nbsp; を使えば、WordPressのベータ版を記録的な速さでインストールできます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">手順:</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>好きな方法でローカルに WordPress サイトを作成してください。サイトの準備完了の通知を待ちます。</li>\n\n\n\n<li>ターミナルを開き、WordPress をインストールしたルートディレクトリに移動します。</li>\n\n\n\n<li>次のコマンドを実行して、最新のベータバージョンに更新します。</li>\n</ol>\n\n\n\n<pre class=\"wp-block-code\"><code>wp core update --version=7.0-beta1</code></pre>\n\n\n\n<p class=\"wp-block-paragraph\">または</p>\n\n\n\n<pre class=\"wp-block-code\"><code>wp core update --version=7.0-RC1&nbsp;</code></pre>\n\n\n\n<p class=\"wp-block-paragraph\">(必要に応じてバージョン番号を置き換えてください。例えば、-version=7.0-beta2)</p>\n\n\n\n<p class=\"wp-block-paragraph\">WP-CLI では複数の異なるバージョンをインストールし、それらを即座に切り替えられます。とても簡単に特定のビルドをテストし、比較できます。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>ホスト上のステージングサイト</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">本番サイト用のステージングサイトを構築し、本番サイトに影響を与えることなく、WordPress ベータ版 / RC 版でテストできます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">こうすれば、WordPress 7.0 が本番環境に導入されるよりもずっと前に、すべてが正常に動作することを確認できます。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>パッチのテスト</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPressのバージョン全体をテストする必要はないかもしれませんが、1つ以上のパッチをテストする必要はあるかもしれません。</p>\n\n\n\n<p class=\"wp-block-paragraph\">その場合、特定のローカル WordPress 開発環境が必要になります。</p>\n\n\n\n<p class=\"wp-block-paragraph\">セットアップについては、<a href=\"https://make.wordpress.org/core/handbook/tutorials/installing-wordpress-locally/\">こちらの手順</a>に従ってください。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>ブラウザでのチケットのテスト</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://github.com/WordPress/wordpress-develop\">wordpress-develop</a>&nbsp; リポジトリ、または&nbsp; <a href=\"https://github.com/WordPress/gutenberg\">gutenberg</a>&nbsp; リポジトリに、ブラウザでテストしたい 特定の PR がありますか ?</p>\n\n\n\n<p class=\"wp-block-paragraph\">Playground を使えば、システムにソフトウェアをインストールすることなく、<a href=\"https://make.wordpress.org/test/handbook/get-setup-for-testing/test-core-tickets-with-playground/\">任意のコアチケットをテスト</a>できます。以下のリンクを使用してください。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://playground.wordpress.net/wordpress.html\">https://playground.wordpress.net/wordpress.html</a>&nbsp; <a href=\"https://playground.wordpress.net/gutenberg.html\">https://playground.wordpress.net/gutenberg.html</a></p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>一般的なテストチェックリスト</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">更新された WordPress バージョンとサイトの互換性を素早くテストしたい場合は、以下のチェック項目を確認してください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">まず、WordPress をベータ版 / RC版に更新し、 wp-config.php で<a href=\"https://developer.wordpress.org/advanced-administration/debug/debug-wordpress/#example-wp-config-php-for-debugging\">デバッグ</a>&nbsp; を有効にして、テーマとプラグインをアップグレードしてください。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>アップデート後にプラグインとテーマが自動的に無効化されていないことを確認します。</li>\n\n\n\n<li>WordPress サイトヘルスツールで新規の警告や問題がないことを確認します。</li>\n\n\n\n<li>レイアウトの崩れや要素の位置ずれがないことを確認します。</li>\n\n\n\n<li>リンクとパーマリンクをテストして、404 エラーがないことを確認します。</li>\n\n\n\n<li>投稿、画像、メディアが正しく表示されていることを確認します。</li>\n\n\n\n<li>サイトマップと robots.txt ファイルが正しく機能していることを確認します。</li>\n\n\n\n<li>管理ダッシュボードにエラーがなく、完全にアクセスできることを確認します。</li>\n\n\n\n<li>サイトにカスタムブロックがある場合は、新しいブロックでコンテンツを作成し、既存のコンテンツを編集してください。</li>\n\n\n\n<li>新しい投稿を作成します。コンテンツを追加し、テキストをコピー &amp; ペーストし、メディアファイルを手動で追加します。投稿を保存し、コンソールで問題がないかを確認します。</li>\n\n\n\n<li>新しいページを作成し、コンテンツを追加して、さまざまなブラウザでの表示を確認します。</li>\n\n\n\n<li>ブラウザの開発者コンソールを開き、エラー、警告、通知がないことを確認します。</li>\n\n\n\n<li>エラーログファイルを開き、通知、警告、致命的なエラーがないことを確認します。</li>\n\n\n\n<li>ユーザーの権限グループと許可がこれまでどおり設定されていることを確認します。</li>\n\n\n\n<li>予約投稿や自動化されたタスク (バックアップなど) が意図した通りに機能することを確認します。</li>\n\n\n\n<li>統合されたすべてのサービス (支払いゲートウェイや分析ツールなど) が動作していることを確認します。</li>\n\n\n\n<li>異なるブラウザでサイトを開き、すべての機能が期待通りに動作することを確認します。</li>\n\n\n\n<li>更新後のサイトのパフォーマンスと読み込み速度を確認します。</li>\n\n\n\n<li>キーボードナビゲーション、コントラスト、スクリーンリーダーの動作などのアクセシビリティの基本を確認します (可能な場合)。</li>\n\n\n\n<li>フォームの送信 (連絡先フォーム、チェックアウトフォーム、ログインフォームなど) をテストします。</li>\n\n\n\n<li>メディアのアップロード、画像の編集、ギャラリー機能が正常に動作することを確認します。</li>\n\n\n\n<li>テーマのカスタマイズ設定 (カスタマイザーまたはサイトエディター) の安定性をテストします。</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress に依存する多様なグローバルコミュニティのために、新しいバージョンも引き続き、信頼性高く動作する必要があります。</p>\n\n\n\n<p class=\"wp-block-paragraph\">ここで何かが失敗すると、収益に直接影響する可能性があります。本番環境を更新する前に、これらの問題の修正を優先してください。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>テスト対象の主な機能</strong></h2>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>ビジュアルリビジョン</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0のビジュアルリビジョン機能により、直接エディター内で、過去の投稿バージョンを確認、復元できます。変更点は視覚的にわかりやすくハイライト表示されます。別画面の代わりに新しい「リビジョン」ビューが表示され、タイムライン / スライダーを使って新旧のリビジョン間を移動できます。コンテンツキャンバスには、追加されたテキストは緑色、削除されたテキストは赤色、リンクや太字などの書式変更は黄色でハイライト表示され、差分が視覚的に表示されます。変更、追加、削除されたブロックは視覚的にマークされ、ページのどの部分が変更されたかをすぐに確認できます。このモードでは、リビジョンの確認と復元は可能ですが、コンテンツを直接編集することはできません。そのため、レビューと復元に重点を置いたエクスペリエンスとなります。</p>\n\n\n\n<figure class=\"wp-block-embed is-type-rich\"><div class=\"wp-block-embed__wrapper\">\n<div style=\"width: 640px;\" class=\"wp-video\"><video class=\"wp-video-shortcode\" id=\"video-7902-1\" width=\"640\" height=\"360\" preload=\"metadata\" controls=\"controls\"><source type=\"video/mp4\" src=\"https://make.wordpress.org/test/files/2026/02/Visual-Revisions-Demo.mp4?_=1\" /><a href=\"https://make.wordpress.org/test/files/2026/02/Visual-Revisions-Demo.mp4\">https://make.wordpress.org/test/files/2026/02/Visual-Revisions-Demo.mp4</a></video></div>\n</div></figure>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>コンテンツとリビジョンを作成する</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>新しい投稿またはページを作成します。</li>\n\n\n\n<li>いくつかの異なるブロック (段落、見出し、リスト、画像) を追加します。</li>\n\n\n\n<li>いくつか変更を加え、そのたびに「更新」をクリックします (テキストの追加、テキストの削除、書式の変更、ブロックの追加/削除)。</li>\n</ul>\n\n\n\n<ol start=\"2\" class=\"wp-block-list\">\n<li>エディター内のリビジョンビューを開く</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>エディターで、投稿のサイドバー (ドキュメント / 設定) を開きます。</li>\n\n\n\n<li>「リビジョン」リンク / カウントをクリックします。</li>\n\n\n\n<li>エディター内に留まっていることを確認します。専用のリビジョンヘッダーとスライダーが表示されます。</li>\n</ul>\n\n\n\n<ol start=\"3\" class=\"wp-block-list\">\n<li>スライダー / タイムラインを使用する</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>スライダーを古いリビジョンと新しいリビジョンに移動します。</li>\n\n\n\n<li>キャンバスが更新され、選択したリビジョンが表示され、現在のリビジョンが明確に表示されていることを確認します</li>\n</ul>\n\n\n\n<ol start=\"4\" class=\"wp-block-list\">\n<li>視覚的な差異を確認する</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>確認項目:\n<ul class=\"wp-block-list\">\n<li>追加されたテキストは緑色で強調表示され、下線が引かれています。</li>\n\n\n\n<li>削除されたテキストは赤色で強調表示され、取り消し線が引かれています。</li>\n\n\n\n<li>純粋な書式変更 (例: 語をリンクに変換する、太字にする) は黄色 (アウトライン/下線) で表示されます。</li>\n</ul>\n</li>\n\n\n\n<li>変更、追加、削除されたブロックは、変更されていないブロックと視覚的に区別されていることを確認します。</li>\n</ul>\n\n\n\n<ol start=\"5\" class=\"wp-block-list\">\n<li>マーカー / ナビゲーションをスクロールする</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>変更箇所を示すマーカーをスクロール領域で探します</li>\n\n\n\n<li>マーカーをクリックして、ビューがおおよそ変更された領域にジャンプすることを確認します。</li>\n</ul>\n\n\n\n<ol start=\"6\" class=\"wp-block-list\">\n<li>選択と編集できないこと</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>リビジョンビューでブロックをクリックします。</li>\n\n\n\n<li>ブロックを選択、内容を確認することはできても、入力、新しいブロックの追加、ブロックの移動はできないことを確認します。</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">テスト中に問題や予期しない動作が発生した場合は、<a href=\"https://github.com/WordPress/gutenberg/issues/\">こちら</a>に記録してください。詳細については、<a href=\"https://github.com/WordPress/gutenberg/issues/74742\">#74742</a>&nbsp; を参照してください。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>より多くのテーマタイプに対応するフォントライブラリ</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">以前のバージョンで WordPress はフォントライブラリを導入し、テーマや追加のプラグインに頼ることなく、WordPress 内で直接フォントをアップロード、管理、適用できるようになりました。WordPress 7.0をターゲットとしたアップデートではこの機能が拡張され、ブロックテーマだけでなく、クラシックテーマもサポートされるようになりました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">この機能強化により、クラシックテーマを利用中のサイト所有者は、メディアアセットの取り扱いと同様に、より一貫した方法でフォント管理機能にアクセスできます。ブロックテーマだけでなくクラシックテーマでも「外観」-&gt;「フォント」を選択すると専用のフォントページが表示され、フォントを一元的にアップロード、有効化、管理できます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">一度追加されたフォントは、ブロックエディターの「タイポグラフィ」コントロール内で使用でき (例: 段落ブロックの設定でフォントファミリーを選択する)、異なるテーマのタイプ間でより統一されたタイポグラフィ体験を提供します。</p>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>クラシックテーマでフォントライブラリが利用できることを確認する</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>クラシックテーマ (例: Twenty Twenty-One など) をインストールして、有効化します。</li>\n\n\n\n<li>「外観」-&gt;「フォント」に移動します。</li>\n</ol>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>期待される結果：</strong></h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li>クラシックテーマでもフォントページが表示されます。</li>\n\n\n\n<li>UI の破壊やスタイルの欠落はありません。</li>\n</ul>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>カスタムフォントをアップロードする</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>「外観」-&gt;「フォント」に移動します。</li>\n\n\n\n<li>サポートされているフォントファイルをアップロードします。</li>\n\n\n\n<li>アップロードしたフォントを有効化します。</li>\n</ol>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>期待される結果:</strong></h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li>フォントのアップロードに成功します。</li>\n\n\n\n<li>フォントはライブラリで利用できます。</li>\n\n\n\n<li>コンソールまたはサーバーログにエラーはありません。</li>\n</ul>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>ブロックエディターでフォントを使用する</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>投稿 / 固定ページを作成または編集します。</li>\n\n\n\n<li>ブロック (例: 段落) を追加します。&nbsp;</li>\n\n\n\n<li>「タイポグラフィ」 -&gt; 「フォントファミリー」を開きます。</li>\n\n\n\n<li>アップロードしたフォントを選択します。</li>\n</ol>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>期待される結果:</strong></h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li>ドロップダウンにフォントが表示されます。</li>\n\n\n\n<li>エディターのプレビューでフォントが正しく適用されます。</li>\n</ul>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>フロントエンドでのレンダリングのチェック</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>投稿を公開、更新します。</li>\n\n\n\n<li>フロントエンドで確認します</li>\n</ol>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>期待される結果：</strong></h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li>選択したフォントが正しく表示されます。</li>\n\n\n\n<li>フォールバックやスタイルの競合はありません。</li>\n</ul>\n\n\n\n<figure class=\"wp-block-embed is-type-rich\"><div class=\"wp-block-embed__wrapper\">\n<div style=\"width: 640px;\" class=\"wp-video\"><video class=\"wp-video-shortcode\" id=\"video-7902-2\" width=\"640\" height=\"360\" preload=\"metadata\" controls=\"controls\"><source type=\"video/mp4\" src=\"https://make.wordpress.org/test/files/2026/02/Font-Library-For-Classic-theme.mp4?_=2\" /><a href=\"https://make.wordpress.org/test/files/2026/02/Font-Library-For-Classic-theme.mp4\">https://make.wordpress.org/test/files/2026/02/Font-Library-For-Classic-theme.mp4</a></video></div>\n</div></figure>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>レスポンシブ編集モード</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">レスポンシブ編集モードでは、ブロックエディター内で直接、さまざまなデバイスサイズにおけるコンテンツの表示方法を制御できます。この機能により、ユーザーは画面の種類 (デスクトップ、タブレット、モバイル) に基づいて選択的にブロックを非表示にでき、カスタム CSS やテーマレベルの調整なしで、サイトデザインに合致し、最適化された表示エクスペリエンスを作成できます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">この機能により、サイト所有者やコンテンツ作成者はレスポンシブレイアウトをより適切に管理し、ユーザーのデバイスに応じて特定のコンテンツ要素を適切に表示できます。これは特に、読みやすさの最適化、モバイルユーザビリティの向上、様々な画面サイズでのクリーンなレイアウトの実現に役立ちます。</p>\n\n\n\n<figure class=\"wp-block-embed is-type-rich\"><div class=\"wp-block-embed__wrapper\">\n<div style=\"width: 640px;\" class=\"wp-video\"><video class=\"wp-video-shortcode\" id=\"video-7902-3\" width=\"640\" height=\"360\" preload=\"metadata\" controls=\"controls\"><source type=\"video/mp4\" src=\"https://make.wordpress.org/test/files/2026/02/Responsive-Editing-Mode.mp4?_=3\" /><a href=\"https://make.wordpress.org/test/files/2026/02/Responsive-Editing-Mode.mp4\">https://make.wordpress.org/test/files/2026/02/Responsive-Editing-Mode.mp4</a></video></div>\n</div></figure>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>WordPress ダッシュボードに移動し、「ページ」や「投稿」をクリックします。</li>\n\n\n\n<li>ブロックの表示、非表示を変更したページを開きます。</li>\n\n\n\n<li>特定の画面サイズで非表示にしたいブロックをクリックします。</li>\n\n\n\n<li>ブロックツールバーの3つのドット (⋮) アイコンをクリックします。追加のオプションが開きます。</li>\n\n\n\n<li>ドロップダウンメニューから「非表示」オプションを選択します。</li>\n\n\n\n<li>ブロックを非表示にするデバイスタイプ (デスクトップ、タブレット、モバイル) を選択し、ページを保存します。</li>\n\n\n\n<li>フロントエンドでページを表示し、選択した画面サイズでブロックが非表示になっていることを確認します。</li>\n\n\n\n<li>リストビューを使用して確認します。</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>トップツールバーのリストビューアイコンをクリックします。</li>\n\n\n\n<li>リスト内でブロックを探します。</li>\n\n\n\n<li>交差した目のアイコンは、ブロックが1つ以上のデバイスで非表示であることを示します。</li>\n</ul>\n\n\n\n<ol start=\"9\" class=\"wp-block-list\">\n<li>非表示設定を変更する (必要であれば)</li>\n</ol>\n\n\n\n<ul class=\"wp-block-list\">\n<li>交差した目のアイコンが付いたブロックをクリックします。</li>\n\n\n\n<li>ブロックの非表示設定パネルが開き、表示設定を確認または調整できます。</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">テスト中に問題や予期しない動作が発生した場合は、<a href=\"https://github.com/WordPress/gutenberg/issues/\">こちら</a>に記録してください。詳細については、<a href=\"https://github.com/WordPress/gutenberg/issues/73776\">#73776</a>を参照してください。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>新しい管理者向け機能改善</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0は管理インターフェースをビジュアル的に刷新しています。これは wp-admin のモダナイズ、ブロックエディターのデザインシステムとの一貫性の向上、そして全体的なユーザビリティの向上を目的としています。このアップデートは、機能面での大きな変更はなく、主にスタイルと UI の洗練に重点を置いているため、テストではビジュアルの一貫性、プラグインの互換性、アクセシビリティ、回帰チェックに重点を置きます。</p>\n\n\n\n<figure class=\"wp-block-embed is-type-rich\"><div class=\"wp-block-embed__wrapper\">\n<div style=\"width: 640px;\" class=\"wp-video\"><video class=\"wp-video-shortcode\" id=\"video-7902-4\" width=\"640\" height=\"360\" preload=\"metadata\" controls=\"controls\"><source type=\"video/mp4\" src=\"https://make.wordpress.org/test/files/2026/02/Coat-of-Paint.mp4?_=4\" /><a href=\"https://make.wordpress.org/test/files/2026/02/Coat-of-Paint.mp4\">https://make.wordpress.org/test/files/2026/02/Coat-of-Paint.mp4</a></video></div>\n</div></figure>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>ダッシュボード、投稿 / 固定ページ一覧、編集画面、設定、メディアライブラリ、プラグイン / テーマページなどの主要な管理画面を確認し、視覚的な一貫性、間隔、タイポグラフィ、ボタンの配置、通知のスタイルを確認します。</li>\n\n\n\n<li>よく使用されるプラグイン (WooCommerce、SEO プラグイン、フォームプラグイン、カスタム管理プラグインなど) を有効化してプラグインの互換性をテストし、管理レイアウト、ボタン、テーブル、フォームが正しく表示されることを確認します。</li>\n\n\n\n<li>投稿や固定ページの作成、編集、メディアのアップロード、設定の更新、管理セクション間の移動などの中心的なワークフローを検証し、機能の低下がないことを確認します。</li>\n\n\n\n<li>色のコントラスト、キーボード ナビゲーション、フォーカス状態、読みやすさ、スクリーンリーダーの動作などのアクセシビリティをチェックします。</li>\n\n\n\n<li>ブラウザのサイズを変更し、タブレットやモバイルの幅でテストし、メニューの折りたたみ、テーブル、ボタンが使用可能なままであることを確認し、管理画面のレスポンシブな動作をテストします。</li>\n\n\n\n<li>管理画面の読み込み時間、レイアウトのシフト、コンソールエラー、異常な遅延などのパフォーマンス面を観察します。</li>\n\n\n\n<li>以前のバージョンの WordPress と動作を比較して回帰チェックを実施し、ワークフロー、設定、メディア機能が安定していることを確認します (Tip: Playground の新規インスタンスを WordPress の古いバージョン (6.9など) で開き、比較します)。</li>\n\n\n\n<li>どんな問題でも報告します。たとえばレイアウトの破壊、プラグインの競合、アクセシビリティの低下、一貫性のないスタイル、パフォーマンスの問題など。</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">詳細については<a href=\"https://core.trac.wordpress.org/ticket/64470\">#64470</a>を参照してください。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>ナビゲーションブロック用のカスタマイズ可能なオーバーレイ</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0では&nbsp; <strong>カスタマイズ可能なナビゲーションオーバーレイ</strong>&nbsp; が導入されました。ブロックエディター内でモバイルナビゲーションメニューをより細かく制御できる新機能です。以前のモバイルメニューオーバーレイではカスタマイズオプションが限られ、ユーザーはデフォルトのレイアウトとスタイルしか使えないことがよくありました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">この拡張により、ユーザーはブロックとパターンを使用して、完全にカスタマイズされたナビゲーションオーバーレイをデザインでき、ブランド要素、CTA (Call to Action、行動喚起)、画像、カスタマイズされたナビゲーション構造を追加できます。オーバーレイは再利用可能なテンプレートパーツとして保存され、テーマ間で一貫したデザインを実現できるだけでなく、テーマ作成者が定義済みのオーバーレイデザインを提供することもできます。</p>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>テンプレートにナビゲーションブロックを挿入します。</li>\n\n\n\n<li>ナビゲーションブロックを選択し、右側のパネル内の「設定」を開きます。</li>\n\n\n\n<li>「オーバーレイ」カスタマイズコントロールで、「カスタムオーバーレイ」を作成します。</li>\n\n\n\n<li>エディターでプレビューします。</li>\n\n\n\n<li>フロントエンドのモバイルビューで表示します。</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">テスト中に問題や予期しない動作が発生した場合は、<a href=\"https://github.com/WordPress/gutenberg/issues/\">こちら</a>に記録してください。 詳細については、<a href=\"https://github.com/WordPress/gutenberg/issues/73084\">#73084</a>を参照してください。</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>リアルタイムコラボレーション</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\">リアルタイムコラボレーション (Real-time Collaboration) は、Gutenberg プロジェクトフェーズ3の目玉機能であり、コアに初めて搭載されます。略して RTC とも呼ばれます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">しかし、リリースに到達する前に、RTC はあなた (とあなたの友人 !) が必要です。この画期的な機能のあらゆる部分、フロントエンドの使いやすさからリテラル PHP 関数、データベース呼び出し、API エンドポイントなどで、この最初の実装を徹底的にテストする必要があります。</p>\n\n\n\n<p class=\"wp-block-paragraph\">要するに、容赦なく徹底的にテストしてください。すべてを壊すつもりでテストしましょう ! その結果、この機能に取り組んできたコントリビューターが、コアに入れるに十分かどうかを判断できます。</p>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li>他のユーザーがアクセスできるサーバーに WordPress 7.0ベータ1をインストールします。</li>\n\n\n\n<li>これはおそらく新規インストールになるはずです。ローカルネットワーク上、ステージングサーバー上、またはその中間の場所になるでしょうが、本番サーバーや、単一のコンピュータ上のローカルインストールではありません。</li>\n\n\n\n<li>プラグインで、「設定」 -&gt; 「書き込み」に移動し、「Enable real-time collaboration. (リアルタイムコラボレーションを有効化する)」をオンにします。</li>\n\n\n\n<li>投稿を開いて編集します。もちろん通常の投稿から始めますが、固定ページも投稿であり、カスタム投稿タイプも投稿であることを覚えておいてください。いくつか例外がありますが、これについては以下で説明します。</li>\n\n\n\n<li>友人や同僚 (2人でも10人でも !) を招待して、同じ投稿を編集します。\n<ul class=\"wp-block-list\">\n<li>ビデオ通話を開催して画面を共有すると、両方のエクスペリエンスをそれぞれが確認できます。</li>\n\n\n\n<li>あるいは、自分一人でもコラボレーションできます ! 別のタブでインストールした WordPress を開き、別のユーザーとしてログインします。両方のユーザーが編集できるかを確認してください。</li>\n\n\n\n<li>別のオプション: 同じネットワーク上の2台のマシンでサイトを開きます。</li>\n</ul>\n</li>\n\n\n\n<li>もしあれば本物のコンテンツ (実際のテキストや画像、他のデータソース、他のメディアなど) を利用します。普段のワークフローを使えるかどうかを確認してください。</li>\n</ul>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>期待される効果</strong></h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>リアルタイムコラボレーションは、ブロックエディターとサイトエディターで投稿を編集している場合にのみ機能します。</strong>&nbsp; 他の管理画面では機能しません。</li>\n\n\n\n<li><strong>従来の投稿メタボックスは同期しません。</strong>&nbsp; これらのボックスは引き続き使用できますが、共同編集者は更新内容をリアルタイムで確認できません。場合によっては、共同編集者同士が互いの変更を上書きする可能性があります。\n<ul class=\"wp-block-list\">\n<li>コードを見なければ、投稿メタボックスが従来のものなのか (save_post&nbsp; フックを使用して永続化)、モダンなものか (Gutenberg データストアに統合) は必ずしも明らかではありません。多くのプラグインはまだ従来の投稿メタボックスを使用しています。</li>\n</ul>\n</li>\n\n\n\n<li><strong>ほとんどのブロックは互換性があります。</strong>&nbsp; ブロックは属性を介して同期されるため、ほとんどのブロックはデフォルトでリアルタイムコラボレーションをサポートします。一部のブロックはユーザー入力の処理にローカルステートを使用しており、このときリアルタイムコラボレーション中に問題が起きる可能性があります。\n<ul class=\"wp-block-list\">\n<li>core/freeform&nbsp; (クラシック) ブロックは、<a href=\"https://github.com/WordPress/gutenberg/issues/75307\">現在互換性がありません</a>。</li>\n</ul>\n</li>\n\n\n\n<li><strong>ブロックエディターと統合されたプラグインには問題が発生する可能性があります。</strong>&nbsp; プラグインの動作は、最も重要なフィードバックの一つです。</li>\n\n\n\n<li><strong>テンプレートの表示ビューで共同作業者のカーソルが消えます。</strong></li>\n\n\n\n<li><strong>同じブロックで共同作業を行うと問題が発生する可能性があります。</strong>&nbsp; それでもテストをお願いしますが、カーソル位置まわりの挙動にクセが出るかもしれません。フィードバックが修正を速めます !</li>\n\n\n\n<li><strong>同期は HTTP ポーリングで行われるため、瞬時ではありません。</strong>&nbsp; したがって時々、遅延を感じることがあります。その場合はぜひ報告してください。同様に、ある部分が他の部分よりもスムーズに感じる場合も報告してください。パフォーマンスは、コミュニティが RTC を長期間受け入れるにあたり、直接影響します。</li>\n</ul>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>注意すべき点</strong></h4>\n\n\n\n<p class=\"wp-block-paragraph\">全体的な機能について</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>リアルタイムコラボレーションは、全期間で機能しましたか ?</li>\n\n\n\n<li>接続が切れませんでしたか ? 作業を中断するレベルで、反応がないと感じたことはありましたか ?</li>\n\n\n\n<li>コンテンツは消えませんでしたか ? 重複はありませんでしたか ?</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">実際のワークフローにおいて、以下のような場面でコラボレーションできましたか ?</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>カスタムブロック上</li>\n\n\n\n<li>プラグインの UI 内</li>\n\n\n\n<li>サイトエディター内</li>\n\n\n\n<li>大きなドキュメント上</li>\n\n\n\n<li>複数のユーザーを追加した場合</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">RTC のアクセシビリティはいかがですか ? 以下で動作しましたか ?</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>キーボードのみ使用</li>\n\n\n\n<li>スクリーンリーダーを使用して</li>\n\n\n\n<li>モバイルデバイス上で</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">テスト中に問題や予期しない動作が発生した場合は、<a href=\"https://github.com/WordPress/gutenberg/issues/52593\">こちら</a>に記録してください。詳細については&nbsp; <a href=\"https://github.com/WordPress/gutenberg/issues/52593\">#52593</a>&nbsp; を参照してください。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>新しいブロックとアップデート</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0では3つの新しいブロックが追加されました。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>アイコン</li>\n\n\n\n<li>パンくずリスト</li>\n\n\n\n<li>タブ</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">アイコンブロックを使用すると、1つまたは複数のアイコンを追加し、限られた方法でスタイルを設定できます。今後、さらに多くのオプションが追加される予定です。</p>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>投稿またはページを開きます。</li>\n\n\n\n<li>アイコンブロックを挿入します。</li>\n\n\n\n<li>表示されるオプションを試してください。</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">パンくずリストブロックには2つのオプション、ホームリンクを表示する、区切り線を選択する、が用意されています。現時点では、このブロックは階層構造の投稿タイプでのみ機能します。</p>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>階層的な投稿を開きます (例: 固定ページ)。</li>\n\n\n\n<li>パンくずリストブロックを挿入します。</li>\n\n\n\n<li>ホームリンクを表示するオプションをオンにします。ページに表示されますか ?</li>\n\n\n\n<li>ホームリンクをオフにします。どのように変化しますか ?</li>\n\n\n\n<li>セパレーターオプションの選択を試してください。</li>\n\n\n\n<li>見つけたことを報告してください。</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">タブブロックを使用すると、ブロックエディター内でタブ付きのコンテンツエリアを構築できます。7.0でのタブブロックでは、コンテンツエリア内にさまざまなブロックをネストできます。</p>\n\n\n\n<h4 class=\"wp-block-heading\"><strong>テスト手順</strong></h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li>投稿を開きます。</li>\n\n\n\n<li>タブブロックを挿入します。</li>\n\n\n\n<li>「タブ」ボタンをクリックして、タブを追加します。</li>\n\n\n\n<li>コンテンツを追加します。ほぼすべてのブロックが機能するはずです。</li>\n\n\n\n<li>フロントエンドで確認します。タブをクリックし、開閉することを確認します。</li>\n\n\n\n<li>開いているタブごとにコンテンツを確認します。レイアウトは維持されますか ? すべてが揃っていますか、それとも、一部が欠落したり、切り取られていませんか ?</li>\n</ol>\n\n\n\n<p class=\"wp-block-paragraph\">さらに、次の3つのブロックが更新されます。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>ギャラリーブロックには、画像を切り替えられるライトボックスが追加されます。</li>\n\n\n\n<li>カバーブロックは外部の動画をサポートします。</li>\n\n\n\n<li>グリッドブロックに新しいコントロールが追加されます。</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>ブラウザでのクライアントサイドメディア処理</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ではクライアントサイドメディア処理が導入されました。よりスムーズな画像処理のため、ブラウザの機能を活用して画像のサイズ変更や圧縮などのタスクを処理します。高度な画像フォーマットや圧縮技術を利用でき、ウェブサーバーへの負荷を軽減します。新規コンテンツと既存コンテンツの両方で効率的なメディア処理プロセスを提供し、スムーズなメディアワークフローが実現します。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ1には多くのオプションと拡張がありますが、まだ始まりに過ぎません。今後のリリースではさらに優れた機能が追加される予定です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">分かりやすく役に立つテスト手順の詳細については、<a href=\"https://github.com/WordPress/gutenberg/pull/74566\">こちら</a>をフォローしてください。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>WordPress 7.0における PHP 互換性の更新</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0では、サポートする PHP の最小バージョンを7.4に引き上げます。つまり、PHP 7.2または7.3を使用しているサイトは今回のメジャーアップデートを受けられず、WordPress 6.9ブランチのままとなります。サイト所有者は、最新の状態を維持し、セキュリティを確保するために、ホスティングプロバイダーと連携して PHP バージョンのアップグレードを計画し (理想的にはPHP 8.3以上)、WordPress 7.0にアップデートする前にステージング環境でサイトをテストしてください。この変更により、WordPress は最新の PHP 機能とパフォーマンスの向上を活用しながら、積極的にメンテナンスされている PHP ブランチのサポートに注力できます。詳細については、公式発表を参照してください。&nbsp; <a href=\"https://ja.wordpress.org/2026/02/27/dropping-support-for-php-7-2-and-7-3/\">PHP 7.2と7.3のサポート終了 – Make WordPress Core</a></p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>注意事項</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">テスト中は、次の点に注意してください。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>すべての機能を見つけられましたか ? インターフェースだけで使用方法がわかりましたか ?</li>\n\n\n\n<li>ワークフローに意外な点はありませんでしたか ? スムーズで論理的でしたか ? それとも、遅かったり、戸惑ったり、壊れたりしていませんでしたか ?</li>\n\n\n\n<li>エディター、管理画面、フロントエンドで視覚的な先祖返りはありませんでしたか ?</li>\n\n\n\n<li>スタイルのバリエーションやテーマを変更したとき、パターン、テンプレート、サイトエディターの変更は動作しましたか ?</li>\n\n\n\n<li>補助デバイスやデバイス上のアクセシビリティ設定 (フォーカス順、キーボードトラップ、ラベルの欠落、モーションの低減、コントラスト設定など)をテストしましたか ? これらの条件下で機能は動作しましたか ?</li>\n\n\n\n<li>ログやデバッグコンソールに、以前は表示されていなかった PHP の通知、警告、非推奨に関するメッセージは表示されましたか ? 訪問者が目にするフロントエンドに何か表示されましたか ?</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">バグかどうかわからない場合も含め、何かおかしいと感じたらメモしておきましょう。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>フィードバックの報告先</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">気がついたすべてを共有してください。問題点、良かった点、またはその中間、障害、提案、その他、重要と思ったことすべてです。</p>\n\n\n\n<p class=\"wp-block-paragraph\">次のいずれかからお願いします。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>リアルタイムで問題について議論するには、Making WordPress Slack の&nbsp; #core-test&nbsp; および&nbsp; #core&nbsp; チャンネルに投稿してください。</li>\n\n\n\n<li>WordPress コアの問題については、&nbsp; <a href=\"https://core.trac.wordpress.org/\">https://core.trac.wordpress.org/</a>&nbsp; で Trac チケットを作成してください。</li>\n\n\n\n<li>エディター関連のバグについては、<a href=\"https://github.com/WordPress/gutenberg/issues\">Gutenberg リポジトリ</a>で GitHub issue を開いてください。</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">レポートにはできるだけ多くの詳細を含めてください。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>WordPress のバージョン (例: 7.0‑beta1 または 7.0‑RC1)</li>\n\n\n\n<li>PHP バージョンとデータベースの種類とバージョン</li>\n\n\n\n<li>テーマと有効化したプラグイン</li>\n\n\n\n<li>問題を再現するための正確な手順</li>\n\n\n\n<li>スクリーンショット、画面録画、キャプチャしたエラーメッセージ、ログ</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>変更履歴</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">1.0.0 – 初回投稿</p>\n\n\n\n<p class=\"wp-block-paragraph\">Props to <a href=\'https://profiles.wordpress.org/marybaum/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>marybaum</a> 新しいブロックとリアルタイムコラボレーションのセクションに対して。</p>\n\n\n\n<p class=\"wp-block-paragraph\">Props to <a href=\'https://profiles.wordpress.org/anveshika/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>anveshika</a> カスタマイズ可能なオーバーレイとレスポンシブ編集モードのセクションに対して。</p>\n\n\n\n<p class=\"wp-block-paragraph\">Props to <a href=\'https://profiles.wordpress.org/amykamala/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>amykamala</a>, <a href=\'https://profiles.wordpress.org/muddassirnasim/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>muddassirnasim</a>, <a href=\'https://profiles.wordpress.org/wildworks/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>wildworks</a> この投稿の公開前レビューに対して。</p>\n\n\n\n<p class=\"wp-block-paragraph\">&#8212;</p>\n\n\n\n<p class=\"wp-block-paragraph\">協力者: <a href=\'https://profiles.wordpress.org/torikumo/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>torikumo</a>、 <a href=\'https://profiles.wordpress.org/nukaga/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>nukaga</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7902\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"WordPress 7.0 ベータ1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://ja.wordpress.org/2026/02/23/wordpress-7-0-beta-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 23 Feb 2026 05:18:54 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7888\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:238:\"以下は WordPress.org 公式ブログの記事「WordPress 7.0 Beta 1」を訳したものです。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 WordPress 7.0ベータ1の準備が [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Akira Tachibana\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:20255:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://wordpress.org/news/2026/02/wordpress-7-0-beta-1/\">WordPress 7.0 Beta 1</a>」を訳したものです。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ1の準備ができました。ダウンロードして、テストをお願いします。<strong>この WordPress ソフトウェアのベータ版は開発中です。</strong>このバージョンの WordPress を本番環境やミッションクリティカルなサイトでインストール、実行、テストしないでください。新機能を試すには、代わりにテスト環境やローカルサイトをセットアップしてください。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>WordPress 7.0ベータ1をテストする方法</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ1は以下のいずれかの方法でテストできます。</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>プラグイン</strong></td><td><a href=\"https://ja.wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> プラグインをインストールして有効化する。設定では「最前線」チャンネルと「ベータ / RC のみ」ストリームを選択します。</td></tr><tr><td><strong>直接ダウンロード</strong></td><td><a href=\"https://wordpress.org/wordpress-7.0-beta1.zip\">Beta 1 version (zip)</a> をダウンロードして、WordPress サイトにインストールする。</td></tr><tr><td><strong>コマンドライン (WP-CLI)</strong></td><td><a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> コマンドを実行する。 wp core update &#8211;version=7.0-beta1</td></tr><tr><td><strong>WordPress Playground</strong></td><td><a href=\"https://playground.wordpress.net/?php=8.3&amp;wp=beta&amp;networking=no&amp;language&amp;multisite=no&amp;random=r8nny4q18x\">7.0 Beta 1 WordPress Playground instance</a> を使用する。ブラウザで直接ソフトウェアをテストできます。セットアップは必要ありません。クリックするだけで起動します !</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0の最終リリース日は<strong>2026年4月9日</strong>を予定しています。リリーススケジュールの詳細は<a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">こちら</a>をご覧ください。ベータ版とリリース候補版のテストにご協力いただくことは、最終リリースを安定した、パワフルなものにするために必要不可欠です。テストにご協力くださる皆様に感謝いたします。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>あなたのテストが重要です !</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">問題点のテストは、あらゆるソフトウェアの開発において重要です。また、誰もが貢献できる意味のある手段です。経験の有無は関係ありません。<a href=\"https://ja.wordpress.org/2026/02/27/help-test-wordpress-7-0/\">WordPress 7.0でテストする内容の詳細については、こちらをご覧ください</a>。</p>\n\n\n\n<p class=\"wp-block-paragraph\">問題に遭遇したら、まずサポートフォーラムの<a href=\"https://wordpress.org/support/forum/alphabeta/\">アルファ・ベータエリア</a>に報告してください。再現可能なバグの報告に慣れている方は<a href=\"https://core.trac.wordpress.org/newticket\"> WordPress Trac</a> への報告をお願いします。<a href=\"https://core.trac.wordpress.org/tickets/major\">既知のバグ</a>の一覧も Trac で閲覧できます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">リリースのテスト全般について知りたければ、<a href=\"https://make.wordpress.org/test/\">Make Core におけるテスト関連タスク</a>をフォローし、<a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a> の<a href=\"https://wordpress.slack.com/messages/core-test/\"> #core-test チャンネル</a>に参加してください。WordPress 7.0には、これまで Gutenberg プラグインでのみ利用できた多くの新機能が追加されます。WordPress 6.9以降の Gutenberg の更新については一連の<a href=\"https://make.wordpress.org/core/tag/gutenberg-new/\"> What’s new in Gutenberg</a> 投稿 (<a href=\"https://make.wordpress.org/core/2025/11/05/whats-new-in-gutenberg-22-0-05-november/\">22.0</a>, <a href=\"https://make.wordpress.org/core/2025/11/20/whats-new-in-gutenberg-22-1-18-november-2025/\">22.1</a>, <a href=\"https://make.wordpress.org/core/2025/12/03/whats-new-in-gutenberg-22-2-dec3/\">22.2</a>, <a href=\"https://make.wordpress.org/core/2025/12/17/gutenberg-22-3-december-17/\">22.3</a>, <a href=\"https://make.wordpress.org/core/2026/01/22/whats-new-in-gutenberg-22-4-20-january/\">22.4</a>, <a href=\"https://make.wordpress.org/core/2026/02/04/whats-new-in-gutenberg-22-5-04-february/\">22.5</a>, 22.6) を参照してください。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>WordPress 7.0の新機能</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0には編集と管理エクスペリエンスに関する数多くのアップグレードが含まれ、強化されたリアルタイムコラボレーション、洗練されたカスタマイズ、新しいダッシュボードスタイル、そして毎日 WordPress で作成、デザイン、構築する方々のために拡張された開発者ツールボックスが提供されます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">複数のユーザーがリアルタイムで同時に編集でき、チームでの作業がこれまで以上に簡単になります。ビジュアルリビジョンではページのバージョン間の差異を視覚的に比較でき、作成とレビューのプロセスが迅速になりました。さらに、パターンの操作が簡素化され、レイアウトの更新やコンテンツの変更が直感的になりました。ビューの遷移も改善され、画面間をクリックでスムーズに移動できます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0では、新しく改良されたブロックやデザイン機能を使用して、サイトを柔軟にカスタマイズできます。カバーブロックでは動画の埋め込みを背景に設定できます。グリッドブロックはレスポンシブに対応し、新しいブロック「アイコン」と「パンくずリスト」が加わり、見出しブロックは強化されました。更新されたナビゲーションブロックでは、少ない手順で、簡単に、確実にメニューを編集できます。WordPress 7.0のレスポンシブなモバイル対応コントロールでは、画面サイズに応じてブロックを表示、非表示できます。また、クライアントサイドでのメディア処理により、メディアのプロセス全体が高速化されました。すべてのテーマでインストール済みフォントを管理するフォントライブラリー画面が利用可能となり、サイト編集者はいつでもフォントの参照、インストール、整理が可能です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">開発者はコアの原則に従いながら、簡単にモダンなエクスペリエンスを構築できます。WordPress 7.0の新しい WP AI クライアントはコアに新しいレイヤーを追加し、あらゆるプロバイダーの AI モデルを WordPress フレームワーク内で活用し、プラグインやテーマは任意の AI モデルを利用して多様な機能を展開できます。WordPress 7.0では、ブラウザ内でのアビリティの登録と実行に標準的な方法を提供するクライアントサイドアビリティ API により、豊かで一貫性のあるワークフローが実現されます。さらに、PHP のみで実装されたブロックの登録と自動生成のインスペクターコントロールが導入され、ブロック作成に新しい可能性が加わりました。パターンの上書きへのブロックバインディングの更新はカスタム動的ブロックにまでサポートを広げ、ブロック作成者の選択肢も増えました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">このリリースはクリエイター、チーム、開発者に幅広い柔軟性をもたらし、刷新されたデフォルトスタイルによって、これまでお馴染みの管理画面に新しいビジュアル体験を提供します。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>リアルタイムでの共同作業</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9で始まった流れは続き、WordPress 7.0ではチームが共同で作成、編集する機能がより洗練され、強化されました。このバージョンの WordPress では、複数のユーザーが同じ投稿や固定ページをリアルタイムで編集、コラボレーションできます。データの同期や安定したノート機能でチームワークは円滑になり、編集やレビュープロセスが効率化されます。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>リアルタイムコラボレーション: 複数の場所から投稿や固定ページを同時に編集できます。オフライン編集やデータ同期も有効です。また、新しいデフォルトの HTTP ポーリング同期プロバイダーには、プラグインやホスティング環境で WebSocket をサポートするオプションもあります。共同でコンテンツを作成するワークフローにより、チームは効果的にブレインストーミングし、生産性を向上できます。ベータ期間中、リアルタイムコラボレーションは幅広いフィードバックとテストのために、オプトインされます。</li>\n\n\n\n<li>ノート: WordPress 7.0ではコラボレーションを支援するリアルタイム同期、新規ノート作成のキーボードショートカット、ノート機能の安定性を高める一連の品質改善が実装されました。</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>洗練された管理エクスペリエンス</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0は管理画面のエクスペリエンスを強化し、慣れ親しんだインターフェースはそのままに、デフォルトのカラースキームを刷新し、クリーンでモダンなダッシュボードをお届けします。更新されたダッシュボードの新しいビジュアルリビジョン比較機能や、画面間のスムーズな切り替えは、編集エクスペリエンスを向上します。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>ビジュアルリビジョン: WordPress 7.0ではリビジョン機能がさらに向上し、エディター内でリビジョン同士を視覚的に比較する機能が追加されました。&nbsp;</li>\n\n\n\n<li>ビューの遷移: ダッシュボード内のドキュメント間ビュー遷移が強化され、画面から画面への移動がシームレスになり、視覚的な一貫性が保たれます。</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>コンテンツを簡単にカスタマイズ</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0では、コンテンツとデザインのための新しいツール、強化された編集コントロール、モバイルフレンドリーへの配慮により、クリエイターのみなさんにさらなる柔軟性をお届けします。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>レスポンシブ編集モード: ブロックの表示はなお一層レスポンシブかつモバイルフレンドリーになり、このバージョンでは画面サイズに基づいて表示、非表示を切り替えられます。</li>\n\n\n\n<li>パターン編集と contentOnly interactivity: WordPress 7.0では、パターン単位の編集モード、ボタンおよびリストブロックのツリービュー、デフォルトの content-only モードを無効化する機能が導入されました。新しいスポットライトモードでは、パターン内のコンテンツやノートが個別に確認しやすくなります。分離エディターモードを使用すると、同期パターン、テンプレートパーツ、ナビゲーションなどのシンボルや再利用パーツを編集できます。</li>\n\n\n\n<li>ブロックサポートとデザインツール: WordPress 7.0には、テキストの行インデントサポート、テキストカラムサポート、ワイドおよび全幅サイズ画像のアスペクト比、寸法の幅と高さサポート、寸法プリセット、ツール、コントロールが含まれます。</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>新しいブロックとデザインオプションを手元に</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0では一連の新規、改良されたブロックやブロック機能、洗練されたナビゲーションワークフロー、セクション背景に動画を埋め込むなどの多彩なデザインオプションが提供されます。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>ナビゲーションブロック: 改良された編集と表示で、ナビゲーションのワークフローはこれまで以上に直感的でクリアになりました。WordPress 7.0には、テンプレートパーツとしてカスタマイズ可能なナビゲーションオーバーレイが導入され、カスタムブレークポイント設定に基づいてモバイル版オーバーレイを表示、非表示にできます。</li>\n\n\n\n<li>見出しブロック: 見出しレベルをブロックバリエーションとして利用できます。ページ階層やデザインがより柔軟になりました。</li>\n\n\n\n<li>新しいブロック: WordPress 7.0では新しいブロック「パンくずリスト」と「アイコン」ブロックが追加され、ページ構築の幅が広がりました。</li>\n\n\n\n<li>動画を埋め込み可能なカバーブロック: カバーブロックの背景に動画を埋め込めるようになり、クリエイティブで洗練されたデザインの可能性が広がりました。</li>\n\n\n\n<li>グリッドブロックがレスポンシブに対応し、画面サイズに応じて滑らかにフィットするグリッドベースのレイアウトが可能になりました。</li>\n\n\n\n<li>ギャラリーブロックがライトボックス機能をサポートしました。ユーザーは各ギャラリー画像をクリックして表示できます。</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>開発者向けツールボックス</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress のバックエンドで作業する場合にも、WordPress 7.0は強力な開発者向け機能を提供します。新しい API や改良された API 機能は柔軟性をサポートし、今後の拡張に向けた基盤を担います。クライアントサイドアビリティ API では、WordPress 機能のクライアント側レジストリが提供され、新しい革新的なサイトオプションを活用できます。さらに WordPress 7.0では Web クライアント AI API がコアに導入され、ひとつのインターフェースから複数の生成 AI モデルにアクセスできます。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Web クライアント AI API: 新しい AI クライアントと API は生成 AI モデルへのアクセスと通信のためのコマンドセンターとして、WordPress コアの外部にいる AI プロバイダーやアビリティ API 統合と共に機能します。</li>\n\n\n\n<li>アビリティ API とワークフロー API: 新しいクライアントサイドアビリティパッケージにより、ユーザーは新規およびハイブリッドアビリティ、アビリティのフィルターや検索機能、使いやすいコマンドパレットや UI にアクセスできます。</li>\n\n\n\n<li>サーバー上で作成されるブロックとパターン: WordPress 7.0には、PHP のみで定義されたブロックやパターンをサーバーサイドで生成し、ブロック API を通じて自動登録する機能があります。</li>\n\n\n\n<li>DataForm: 新しい詳細レイアウト、新しいコントロール (combobox、adaptiveSelect）、パネルレイアウトの更新されたトリガー (専用の編集ボタン) が導入されました。さらに、バリデーションの初期実装が完了し、すべてのコントロールがサポートを持ち、すべてのレイアウトでエラーメッセージが表示されます。</li>\n\n\n\n<li>DataViews: DataViews には新しいアクティビティレイアウトが追加され、将来のリリースでサードパーティタイプを登録する基盤が整備されました。</li>\n\n\n\n<li>CodeMirror 更新: CodeMirror はバージョン 5.65.40 に更新され、拡張性や利用できるライブラリの選択肢が向上しました。</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>ブラウザでのメディア処理</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0では、クライアントサイドでのメディア処理が導入され、ブラウザの機能を活用して画像のリサイズや圧縮などを行い、スムーズに画像を処理します。高度な画像形式や圧縮技術を利用でき、Web サーバーへの負荷を軽減します。新規および既存コンテンツのメディア処理は効率的になり、メディアワークフローの改善につながります。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0ベータ1には多くのオプションと改良が含まれていますが、これはまだ始まりにすぎません。今後のリリースでのさらに多くの改善に期待してください。</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>あなたのためにここで一句</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\"><em>As sun kisses moon</em>,<br><em>Beta 1 ignites in bloom</em>…<br><em>Seven-oh lands soon</em>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">日の光が月に触れるとき、<br>ベータ1の花、燃え盛る&#8230;<br>7.0の到来は近い。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Props to </em><a href=\"https://profiles.wordpress.org/ellatrix/\"><em>@ellatrix</em></a><em>, </em><a href=\"https://profiles.wordpress.org/jeffpaul/\"><em>@jeffpaul</em></a><em>, </em><a href=\"https://profiles.wordpress.org/annezazu/\"><em>@annezazu</em></a><em>, </em><a href=\"https://profiles.wordpress.org/chaion07/\"><em>@chaion07</em></a><em>, </em><a href=\"https://profiles.wordpress.org/zunaid321/\"><em>@zunaid321</em></a><em>, </em><a href=\"https://profiles.wordpress.org/audrasjb/\"><em>@audrasjb</em></a><em>, </em><a href=\"https://profiles.wordpress.org/mukesh27/\"><em>@mukesh27</em></a><em>, </em><a href=\"https://profiles.wordpress.org/ankit-k-gupta/\"><em>@ankit-k-gupta</em></a>, <a href=\"https://profiles.wordpress.org/oandregal/\"><em>@oandregal</em></a><em>, </em><a href=\"https://profiles.wordpress.org/westonruter/\"><em>@westonruter</em></a><em>, </em><a href=\"https://profiles.wordpress.org/karmatosed/\"><em>@karmatosed</em></a><em>, </em><a href=\"https://profiles.wordpress.org/bph/\"><em>@bph</em></a><em> この投稿のレビューとコラボレーションに対して</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">&#8212;</p>\n\n\n\n<p class=\"wp-block-paragraph\">協力者: <a href=\"https://profiles.wordpress.org/torikumo/\">@torikumo</a>、<a href=\"https://profiles.wordpress.org/nukaga/\">@nukaga</a> </p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7888\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:45:\"WordPress 6.9.1メンテナンスリリース\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://ja.wordpress.org/2026/02/04/wordpress-6-9-1-maintenance-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 04 Feb 2026 04:26:13 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7851\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:218:\"以下は WordPress.org 公式ブログの記事「WordPress 6.9.1 Maintenance Release」の翻訳です。 誤字脱字誤訳などありましたらフォーラムまでお知らせください。 WordPress [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Itsuko Miyake\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11093:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org 公式ブログの記事「<a href=\"https://wordpress.org/news/2026/02/wordpress-6-9-1-maintenance-release/\">WordPress 6.9.1 Maintenance Release</a>」の翻訳です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress 6.9.1が利用可能です !</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">このマイナーリリースには、<a href=\"https://core.trac.wordpress.org/query?resolution=fixed&amp;milestone=6.9.1&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=status&amp;col=priority&amp;order=priority\">コア</a>と<a href=\"https://github.com/WordPress/gutenberg/pull/74806\">ブロックエディター</a>全体にわたる49件のバグ修正が含まれており、ブロックエディター、メール、クラシックテーマなど、WordPressの複数の領域に影響する問題に対処しています。バグ修正の全リストについては、<a href=\"https://make.wordpress.org/core/2026/01/30/wordpress-6-9-1-rc1-is-now-available/\">リリース候補版の告知</a>を参照してください。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9.1はショートサイクルメンテナンスリリースです。WordPressの次期メジャーバージョンは7.0で、2026年4月9日の <a href=\"https://asia.wordcamp.org/2026/\">WordCamp Asia</a> でリリースされる予定です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">自動バックグラウンド更新をサポートするサイトでは、更新プロセスが自動的に始まります。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/wordpress-6.9.1.zip\">WordPress 6.9.1は WordPress.org からダウンロードできます。</a>または、WordPress ダッシュボードに移動して、「更新」をクリックし、続いて「今すぐ更新」をクリックします。このリリースの詳細については <a href=\"https://wordpress.org/support/wordpress-version/version-6-9-1\">HelpHub にアクセス</a>してください。</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress コントリビューターの皆さんに感謝</h2>\n\n\n\n<p class=\"wp-block-paragraph\">本リリースは&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb/\"></a><a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>、<a href=\"https://profiles.wordpress.org/zunaid321/\"></a><a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a> がリードしました。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9.1は、以下の方々の貢献なしには実現できませんでした。メンテナンスの修正を安定版リリースとして提供するための非同期の連携は、WordPress コミュニティの力と能力の証です。</p>\n\n\n\n<p class=\"has-white-color has-blueberry-1-background-color has-text-color has-background has-link-color wp-elements-2424a1450e826a64251540b2b976b77f wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>,&nbsp;<a href=\"https://profiles.wordpress.org/aaronrobertshaw\">Aaron Robertshaw</a>,&nbsp;<a href=\"https://profiles.wordpress.org/acmoifr\">acmoifr</a>,&nbsp;<a href=\"https://profiles.wordpress.org/adamsilverstein\">Adam Silverstein</a>,&nbsp;<a href=\"https://profiles.wordpress.org/oztaser\">Adil Öztaşer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>,&nbsp;<a href=\"https://profiles.wordpress.org/albigdd\">Alexander Bigga</a>,&nbsp;<a href=\"https://profiles.wordpress.org/amanandhishoe\">amanandhishoe</a>,&nbsp;<a href=\"https://profiles.wordpress.org/andrewserong\">Andrew Serong</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bernhard-reiter\">Bernie Reiter</a>,&nbsp;<a href=\"https://profiles.wordpress.org/brumack\">brumack</a>,&nbsp;<a href=\"https://profiles.wordpress.org/darerodz\">David Arenas</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>,&nbsp;<a href=\"https://profiles.wordpress.org/raftaar1191\">Deepak Gupta</a>,&nbsp;<a href=\"https://profiles.wordpress.org/deepakprajapati\">Deepak Prajapati</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dmsnell\">Dennis Snell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/digitalblanket\">digitalblanket</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ellatrix\">Ella Van Durpe</a>,&nbsp;<a href=\"https://profiles.wordpress.org/fabiankaegy\">Fabian Kaegy</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>,&nbsp;<a href=\"https://profiles.wordpress.org/hbhalodia\">Hit Bhalodia</a>,&nbsp;<a href=\"https://profiles.wordpress.org/iflairwebtechnologies\">iflairwebtechnologies</a>,&nbsp;<a href=\"https://profiles.wordpress.org/isabel_brison\">Isabel Brison</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jdeep\">Jaydeep Das</a>,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/maverick3x6\">Jeff Golenski</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jeffpaul\">Jeffrey Paul</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jhtjards\">jhtjards</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/johnbillion\">John Blackbourn</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jonsurrell\">Jon Surrell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jorgefilipecosta\">Jorge Costa</a>,&nbsp;<a href=\"https://profiles.wordpress.org/greenshady\">Justin Tadlock</a>,&nbsp;<a href=\"https://profiles.wordpress.org/karthickmurugan\">Karthick</a>,&nbsp;<a href=\"https://profiles.wordpress.org/solankisoftware\">Kirtikumar Solanki</a>,&nbsp;<a href=\"https://profiles.wordpress.org/0mirka00\">Lena Morita</a>,&nbsp;<a href=\"https://profiles.wordpress.org/luisherranz\">luisherranz</a>,&nbsp;<a href=\"https://profiles.wordpress.org/madhavishah01\">Madhavi Shah</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sirlouen\">Manuel Camargo</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jillro\">Maud Royer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mehrazmorshed\">Mehraz Morshed</a>,&nbsp;<a href=\"https://profiles.wordpress.org/monarobase\">Monarobase</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mrwweb\">mrwweb</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>,&nbsp;<a href=\"https://profiles.wordpress.org/muryam\">Muryam Sultana</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mydesign78\">mydesign78</a>,&nbsp;<a href=\"https://profiles.wordpress.org/narenin\">Narendra Sishodiya</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ntsekouras\">Nik Tsekouras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ninos-ego\">Ninos</a>,&nbsp;<a href=\"https://profiles.wordpress.org/noruzzaman\">Noruzzaman</a>,&nbsp;<a href=\"https://profiles.wordpress.org/oglekler\">Olga Gleckler</a>,&nbsp;<a href=\"https://profiles.wordpress.org/gabertronic\">Ophelia Rose</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ov3rfly\">Ov3rfly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ozgursar\">Ozgur Sar</a>,&nbsp;<a href=\"https://profiles.wordpress.org/paragoninitiativeenterprises\">Paragon Initiative Enterprises</a>,&nbsp;<a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>,&nbsp;<a href=\"https://profiles.wordpress.org/vybiral\">Pavel Vybíral</a>,&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pmbs\">pmbs</a>,&nbsp;<a href=\"https://profiles.wordpress.org/presskopp\">Presskopp</a>,&nbsp;<a href=\"https://profiles.wordpress.org/r1k0\">r1k0</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ramonopoly\">ramonopoly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/youknowriad\">Riad Benguella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ricjcs\">Ricardo S.</a>,&nbsp;<a href=\"https://profiles.wordpress.org/rollybueno\">Rolly Bueno</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mikachan\">Sarah Norris</a>,&nbsp;<a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sergeybiryukov\">Sergey Biryukov</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sajib1223\">Shazzad Hossain Khan</a>,&nbsp;<a href=\"https://profiles.wordpress.org/siliconforks\">siliconforks</a>,&nbsp;<a href=\"https://profiles.wordpress.org/soyebsalar01\">Soyeb Salar</a>,&nbsp;<a href=\"https://profiles.wordpress.org/spielers\">spielers</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>,&nbsp;<a href=\"https://profiles.wordpress.org/studiomondiale\">studio_m</a>,&nbsp;<a href=\"https://profiles.wordpress.org/iamtakashi\">Takashi Irie</a>,&nbsp;<a href=\"https://profiles.wordpress.org/inc2734\">Takashi Kitajima</a>,&nbsp;<a href=\"https://profiles.wordpress.org/threadi\">threadi</a>,&nbsp;<a href=\"https://profiles.wordpress.org/tobiasbg\">Tobias Bäthge</a>,&nbsp;<a href=\"https://profiles.wordpress.org/shimotomoki\">Tomoki Shimomura</a>,&nbsp;<a href=\"https://profiles.wordpress.org/umeshsinghin\">Umesh Singh</a>,&nbsp;<a href=\"https://profiles.wordpress.org/twvania\">Vania</a>,&nbsp;<a href=\"https://profiles.wordpress.org/westonruter\">Weston Ruter</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wfmattr\">WFMattR</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wolf45\">wolf45</a>,&nbsp;<a href=\"https://profiles.wordpress.org/zoe20\">zoe20</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">貢献するには</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress コア開発に参加するには、Trac にアクセスして<a href=\"https://core.trac.wordpress.org/report/6\">チケットに取り組み</a>、<a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> チャンネルで会話に参加してください。手助けが必要ですか ?「<a href=\"https://ja.wordpress.org/team/handbook/core/\">コアコントリビュータハンドブック日本語版</a>」をご確認ください。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald/\">@davidbaumwald</a>,&nbsp;<a href=\"https://profiles.wordpress.org/westonruter/\">@westonruter</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jeffpaul/\">@jeffpaul</a>,&nbsp;<a href=\"https://profiles.wordpress.org/presskopp/\">@presskopp</a><em>&nbsp;<em>の校正への協力に感謝します。</em></em></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">協力者:&nbsp;<a href=\'https://profiles.wordpress.org/atachibana/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>atachibana</a>, <a href=\'https://profiles.wordpress.org/nukaga/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>nukaga</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7851\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress 6.9.1 リリース候補版1 (RC1版)\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://ja.wordpress.org/2026/01/30/wordpress-6-9-1-rc1-is-now-available/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 30 Jan 2026 13:38:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ja.wordpress.org/?p=7847\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:198:\"以下は WordPress.org Make WordPress Core の記事「WordPress 6.9.1 RC1 is now available」の翻訳です。誤字脱字誤訳などありましたらフォーラムまでお知らせ [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Akira Tachibana\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11545:\"\n<p class=\"wp-block-paragraph\">以下は WordPress.org Make WordPress Core の記事「<a href=\"https://make.wordpress.org/core/2026/01/30/wordpress-6-9-1-rc1-is-now-available/\">WordPress 6.9.1 RC1 is now available</a>」の翻訳です。<br>誤字脱字誤訳などありましたら<a href=\"https://ja.wordpress.org/support/forum/alphabeta/\">フォーラムまでお知らせください</a>。</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9.1リリース候補版 (RC1) のテストの準備が整いました ! このマイナーリリースをテストするにはいくつかの方法があります。</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> プラグイン\n<ul class=\"wp-block-list\">\n<li>このリリースはマイナー RC リリースですので、「ポイントリリース」チャンネルと「ナイトリー」ストリームを選択します。これはリリース候補版とそれに続くトランクへのコミットを含む最新ビルドになります。</li>\n</ul>\n</li>\n\n\n\n<li>WP-CLI\n<ul class=\"wp-block-list\">\n<li><code>wp core update https://wordpress.org/wordpress-6.9.1-RC1.zip</code></li>\n</ul>\n</li>\n\n\n\n<li><a href=\"https://wordpress.org/wordpress-6.9.1-RC1.zip\">直接 べータ / RC バージョンをダウンロード</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">このリリース候補版の内容</h2>\n\n\n\n<p class=\"wp-block-paragraph\">6.9.1 RC1 は、WordPress 6.9で入り込んだバグを修正するメンテナンスリリースのリリース候補版です。このリリース候補版では<a href=\"https://core.trac.wordpress.org/query?resolution=fixed&amp;milestone=6.9.1&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=status&amp;col=priority&amp;order=priority\">コア全体で23件</a>、<a href=\"https://github.com/WordPress/gutenberg/pull/70557\">ブロックエディターで25件</a>の問題を修正しています。</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9.1は <a href=\"https://profiles.wordpress.org/jorbin/\">@jorbin</a> と <a href=\"https://profiles.wordpress.org/wildworks/\">@wildworks</a> がリードします。</p>\n\n\n\n<p class=\"wp-block-paragraph\">以下のコアチケットが含まれています:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://core.trac.wordpress.org/ticket/63979\">#63979</a> – WordPress Core setup does not configure XDebug properly</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64229\">#64229</a> – Enqueueing scripts, styles, and script modules should warn when dependencies are missing</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64329\">#64329</a> – Block Processor tests fail without intl extension</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64333\">#64333</a> – I18N: border.radiusSizes key is missing in theme-i18n.json</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64336\">#64336</a> – One removed SimplePie file was not added to `$_old_files` in WP 6.9</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64337\">#64337</a> – Broken styling on “Add Plugins” screen</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64340\">#64340</a> – HTML API may double-escape class names when adding repeatedly</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64347\">#64347</a> – Fatal error when `wxr_cdata()` is called with non-string value</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64348\">#64348</a> – The `$embeds` element is missing from the `wp_mail_succeeded` filter</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64350\">#64350</a> – checkbox not working as expected in the admin panel</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64366\">#64366</a> – Docs: Replace since x.y.z with actual version number</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64368\">#64368</a> – `Could not instantiate mail function` errors sending mail in 6.9</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64380\">#64380</a> – Widgets sidebar and position can’t be changed with accessibility mode enabled</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64412\">#64412</a> – Sporadic unit test failure in Tests_REST_WpRestUrlDetailsController::test_get_items</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64429\">#64429</a> – Script Modules: Dependencies inherit fetchpriority from not-enqueued, registered modules</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64462\">#64462</a> – Update Sodium Compat to 1.24.0</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64474\">#64474</a> – Comments: Notes are accessible when query has comment_type=all</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64485\">#64485</a> – WP_Block_Processor should indicate that inner HTML matches no block type.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64531\">#64531</a> – assertEqualHTML may ignore leading whitespace text</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64537\">#64537</a> – Block Processor: Extracting full block missing nested content.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64535\">#64535</a> – Update packages for 6.9.1</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64354\">#64354</a> – Outlined buttons now have grey background</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64136\">#64136</a> – PHP Deprecated: Fetching multiple feeds with single SimplePie instance is deprecated since SimplePie 1.9.0</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">以下の Gutenberg PR が含まれています:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/71123\">#71123</a> – iAPI: Fix and refactor runtime initialization logic</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/72376\">#72376</a> – Fix Popover closing unexpectedly when a Menu inside it is closed.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73046\">#73046</a> – Notes position alignment in HTML</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73580\">#73580</a> – Gutenberg plugin: Override core classic theme styles</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73592\">#73592</a> – Block Editor: Restore ToolSelector component for backward compatibility</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73608\">#73608</a> – Accordion Heading: Add default style for classic themes</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73612\">#73612</a> – Block JSON schema: add visibility key to supports definition</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73835\">#73835</a> – Color Panel: Ensure minimum height for popover content</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73865\">#73865</a> – Classic Block: Restore HTML editing option</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73867\">#73867</a> – Block API: Fallback to all attributes when checking for unmodified block</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73955\">#73955</a> – Global Styles: fix infinite loop in Font Style UI</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74130\">#74130</a> – Terms Query Block: Fix Max terms for non-hierarchical taxonomies</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74177\">#74177</a> – Fix: Prevent accordion-heading submitting/sending forms (button type=”button” )</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74282\">#74282</a> – Fix: menu_order validation to allow zero and negative values</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74580\">#74580</a> – iAPI: Update deprecation warning for unique ID format</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74715\">#74715</a> – Media &amp; Text: Revert “Fixed Media &amp; Text Block – Image not rendered properly on frontend when inside stack”</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74057\">#74057</a> – Blocks: Always trigger borwser console warnings for blocks with apiVersion below 2</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74340\">#74340</a> – Fix parent popover not closing on click outside</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74750\">#74750</a> – iAPI Router: Prevent router regions with data-wp-key from being recreated on navigation</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74857\">#74857</a> – iAPI Router: Fix initial router regions with attachTo being duplicated after navigate()</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74860\">#74860</a> – Fix: Fit Text not working on calculated line heights.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74864\">#74864</a> – Fix: Safari “Edit as HTML” for Fit Text deletes content</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74927\">#74927</a> – Patterns: restore pattern category actions for user patterns</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/73652\">#73652</a> – Fix: Stretchy text issue when nested on flex containers.</li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/74799\">#74799</a> – [WP 6.9.1] Remove formatting controls restriction private API</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">次は ?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">注意: 6.9ブランチに変更を加える際には dev-reviewed ワークフロー （<a href=\"https://make.wordpress.org/core/handbook/about/release-cycle/releasing-beta-versions/#double-committer-signoff\">2人のコミッターのサインオフ</a>） が必要です。</p>\n\n\n\n<p class=\"wp-block-paragraph\">最終リリースは2026年2月3日（火）を<a href=\"https://make.wordpress.org/core/2026/01/20/wordpress-6-9-1-release-schedule/\">予定しています</a>。RC1の問題が発見された場合、この日付は変更される可能性があります。調整は WordPress.org Slack の <a href=\"https://wordpress.slack.com/archives/C08MVR1MU2K\">#6-9-release-leads</a> チャンネルで行われ、リリースは常に <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> でパッケージ化され、テストされます。</p>\n\n\n\n<p class=\"wp-block-paragraph\">問題を報告された方、テストを手伝ってくれた方、パッチの作成を手伝ってくれた方、みなさんに感謝します。6.9.1の成功は適切なテストにかかっています。ぜひご協力ください。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Props </em><a href=\"https://profiles.wordpress.org/wildworks/\">@wildworks</a>, <a href=\"https://profiles.wordpress.org/joedolson/\">@joedolson</a>, <a href=\"https://profiles.wordpress.org/westonruter/\">@westonruter</a> <em>公開前のレビューに対して。</em></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">協力者: <a href=\"https://profiles.wordpress.org/torikumo/\">@torikumo</a>, <a href=\"https://profiles.wordpress.org/nukaga/\">@nukaga</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"7847\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://ja.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096033\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Fri, 13 Mar 2026 00:59:17 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Wed, 11 Mar 2026 17:08:28 GMT\";s:4:\"link\";s:61:\"<https://ja.wordpress.org/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:4:\"gzip\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 1\";}}s:5:\"build\";i:1773305936;s:21:\"cache_expiration_time\";i:1773406758;s:23:\"__cache_expiration_time\";i:1773406758;}', 'off');
