_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:169:\"https://ja.wordpress.org/support/topic/wordpress-6-9-4-%e6%97%a5%e6%9c%ac%e8%aa%9e%e7%89%88%e3%81%8c%e5%85%a5%e6%89%8b%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11693873\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"返信先: WordPress 6.9.4 日本語版が入手できない\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:169:\"https://ja.wordpress.org/support/topic/wordpress-6-9-4-%e6%97%a5%e6%9c%ac%e8%aa%9e%e7%89%88%e3%81%8c%e5%85%a5%e6%89%8b%e3%81%a7%e3%81%8d%e3%81%aa%e3%81%84/#post-11693873\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 12 Mar 2026 23:00:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1070:\"\n						\n						<p class=\"wp-block-paragraph\">お返事が遅くなってすみません。</p>\n\n\n\n<p class=\"wp-block-paragraph\">すでに「解決済み」にステータス変更してくださっていますが。<br />以下のページで、ダウンロードリンクが 6.9.4に更新されているようです。</p>\n\n\n\n<p class=\"wp-block-paragraph\"><blockquote class=\"wp-embedded-content\" data-secret=\"mBd2a0HItV\"><a href=\"https://ja.wordpress.org/download/\" rel=\"ugc\">Download</a></blockquote><iframe class=\"wp-embedded-content\" sandbox=\"allow-scripts\" security=\"restricted\" style=\"position: absolute; visibility: hidden;\" title=\"“Download” — 日本語\" src=\"https://ja.wordpress.org/download/embed/#?secret=yfUt9BT5P0#?secret=mBd2a0HItV\" data-secret=\"mBd2a0HItV\" width=\"500\" height=\"282\" frameborder=\"0\" marginwidth=\"0\" marginheight=\"0\" scrolling=\"no\"></iframe></p>\n\n\n\n<p class=\"wp-block-paragraph\">（翻訳ファイルが含まれていることまでは確認していますが、インストールまでは検証していません）</p>\n						\n					\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Yukinobu Asakawa\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:55:\"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:236:\"https://ja.wordpress.org/support/topic/%e3%81%93%e3%81%ae%e3%82%b5%e3%82%a4%e3%83%88%e3%81%a7%e9%87%8d%e5%a4%a7%e3%81%aa%e3%82%a8%e3%83%a9%e3%83%bc%e3%81%8c%e7%99%ba%e7%94%9f%e3%81%97%e3%81%be%e3%81%97%e3%81%9f%e3%80%82-8/#post-11693872\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"返信先: このサイトで重大なエラーが発生しました。\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:236:\"https://ja.wordpress.org/support/topic/%e3%81%93%e3%81%ae%e3%82%b5%e3%82%a4%e3%83%88%e3%81%a7%e9%87%8d%e5%a4%a7%e3%81%aa%e3%82%a8%e3%83%a9%e3%83%bc%e3%81%8c%e7%99%ba%e7%94%9f%e3%81%97%e3%81%be%e3%81%97%e3%81%9f%e3%80%82-8/#post-11693872\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 12 Mar 2026 22:50:34 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:394:\"\n						\n						<p class=\"wp-block-paragraph\">こんにちは。</p>\n\n\n\n<p class=\"wp-block-paragraph\">完全に山勘です。<br />WordPress管理画面 -&gt; 「設定」 -&gt; 「パーマリンク」で、パーマリンク構造を変更せずに、