(186, 86, 'lazyblocks_code_frontend_html', '<div useBlockProps style=\"background-color: {{background-color}}\">\n	<div class=\"hero-content\">\n		<h2 class=\"hero-title\">{{{hero-title}}}</h2>\n		<div class=\"hero-subtitle\">{{hero-subtitle}}</div>\n		<a href=\"{{button-url}}\" class=\"hero-button\">{{button-text}}</a>\n	</div>\n</div>'),
(187, 86, 'lazyblocks_style_block', '.wp-block-lazyblock-hero-block {\n	padding: 60px 20px;\n	text-align: center;\n}\n.wp-block-lazyblock-hero-block .hero-content {\n	max-width: 800px;\n	margin: 0 auto;\n}\n.wp-block-lazyblock-hero-block .hero-title {\n	font-size: 36px;\n	margin-bottom: 20px;\n	color: #333;\n}\n.wp-block-lazyblock-hero-block .hero-subtitle {\n	font-size: 18px;\n	margin-bottom: 30px;\n	color: #666;\n	white-space: pre-wrap;\n}\n.wp-block-lazyblock-hero-block .hero-button {\n	display: inline-block;\n	padding: 12px 24px;\n	background-color: #205cc7;\n	color: #fff;\n	text-decoration: none;\n	border-radius: 4px;\n	font-weight: bold;\n}\n.wp-block-lazyblock-hero-block .hero-button:hover {\n	background-color: #154eb4;\n}'),
